INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202312-C01', 'choice', '{"stem": "关于C++类和对象的说法，错误的是(   )。", "options": [{"label": "A", "text": "在C++中，一切皆对象，即便是字面量如整数5等也是对象"}, {"label": "B", "text": "在C++中，可以自定义新的类，并实例化为新的对象"}, {"label": "C", "text": "在C++中，内置函数和自定义函数，都是类或者对象"}, {"label": "D", "text": "在C++中，可以在自定义函数中嵌套定义新的函数"}]}', '{"correctIndex": 3}', NULL, '["面向对象", "类与对象", "函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202312-C02', 'choice', '{"stem": "有关下面C++代码的说法，错误的是(   )。", "options": [{"label": "A", "text": "C++中类内部可以嵌套定义类"}, {"label": "B", "text": "在类中定义的类被称为内部类，定义类的类被称为外部类"}, {"label": "C", "text": "内部类可以随便访问，不需要通过外部类来访问"}, {"label": "D", "text": "代码中Point 被称为内部类，可以通过外部类Rectangle 来访问，Rectangle::Point"}]}', '{"correctIndex": 2}', NULL, '["面向对象", "内部类", "嵌套类", "GESP-6"]', 4, 1775530000000);
