INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202312-J08', 'judgment', '{"stem": "二叉搜索树可以是空树（没有任何节点）或者单节点树（只有一个节点），或者多节点。如果是多节点，则左节点的值小于父节点的值，右节点的值大于父节点的值，由此推理，右节点树的值都大于根节点的值，左节点树的值都小于根节点的值。"}', '{"correct": true}', NULL, '["二叉搜索树", "树的性质", "GESP-6"]', 4, 1775530000000);
