INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202403-C04', 'choice', '{"stem": "给定一个简单的类定义如下，（ ）语句在类的外部正确地创建了一个 Circle 对象并调用了 getArea 函数？\n\nclass Circle {\nprivate:\n    double radius;\npublic:\n    Circle(double r) : radius(r) {}\n    double getArea() {\n        return 3.14 * radius * radius;\n    }\n};", "options": [{"label": "A", "text": "Circle c = Circle(5.0); c.getArea(c);"}, {"label": "B", "text": "Circle c(5.0); getArea(c);"}, {"label": "C", "text": "Circle c = new Circle(5.0); c.getArea();"}, {"label": "D", "text": "Circle c(5.0); c.getArea();"}]}', '{"correctIndex": 3}', NULL, '["面向对象", "类与对象", "构造函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202403-C05', 'choice', '{"stem": "以下代码希望能在一棵二叉排序树中搜索特定的值，请在横线处填入（ ），使其能正确实现相应功能。\n\nTreeNode* search(TreeNode* root, int target) {\n    if (root == NULL || root->val == target) {\n        return root;\n    }\n    if (_______________) {\n        return search(root->left, target);\n    } else {\n        return search(root->right, target);\n    }\n}", "options": [{"label": "A", "text": "target < root->left"}, {"label": "B", "text": "target < root->val"}, {"label": "C", "text": "target > root->val"}, {"label": "D", "text": "target > root->left"}]}', '{"correctIndex": 1}', NULL, '["二叉排序树", "二叉搜索树", "递归", "GESP-6"]', 4, 1775530000000);
