INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202403-C15', 'choice', '{"stem": "下面的代码片段用于反转单链表，请进行（ ）修改，使其能正确实现相应功能。\n\nListNode* reverseLinkedList(ListNode* head) {\n    ListNode* prev = nullptr;\n    ListNode* current = head;\n    while (current != nullptr) {\n        ListNode* next = current->next;\n        current->next = next;\n        prev = current;\n        current = next;\n    }\n    return prev;\n}", "options": [{"label": "A", "text": "current->next = next; 应该改为 current->next = prev;"}, {"label": "B", "text": "ListNode* next = current->next; 应该改为 ListNode* next = prev->next;"}, {"label": "C", "text": "current != nullptr 应该改为 current->next != nullptr"}, {"label": "D", "text": "ListNode* prev = nullptr; 应该改为 ListNode* prev = head;"}]}', '{"correctIndex": 0}', NULL, '["链表", "链表反转", "指针操作", "GESP-6"]', 4, 1775530000000);
