INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C02', 'choice', '{"stem": "关于以下C++代码，（  ）行代码会引起编译错误。\n```cpp\n#include <iostream>\nusing namespace std;\nclass Base {\nprivate:\n    int a;\nprotected:\n    int b;\npublic:\n    int c;\n    Base() : a(1), b(2), c(3) {}\n};\nclass Derived : public Base {\npublic:\n    void show() {\n        cout << a << endl;   // Line 1\n        cout << b << endl;   // Line 2\n        cout << c << endl;   // Line 3\n    }\n};\n```", "options": [{"label": "A", "text": "Line 1"}, {"label": "B", "text": "Line 2"}, {"label": "C", "text": "Line 3"}, {"label": "D", "text": "没有编译错误"}]}', '{"correctIndex": 0}', NULL, '["面向对象", "继承", "访问控制", "GESP-6"]', 4, 1775530000000);
