INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C04', 'choice', '{"stem": "采用如下代码实现检查输入的字符串括号是否匹配，横线上应填入的代码为（ ）。\n```cpp\n#include <iostream>\n#include <stack>\n#include <string>\nusing namespace std;\nbool is_valid(string s) {\n    stack<char> st;\n    char top;\n    for (char& ch : s) {\n        if (ch == ''('' || ch == ''{'' || ch == ''['') {\n            st.push(ch);    // 左括号入栈\n        }\n        else\n        {\n            if (st.empty())\n                return false;\n            ———————————————————————— // 在此处填入代码\n            if ((ch == '')'' && top != ''('') ||\n                (ch == ''}'' && top != ''{'') ||\n                (ch == '']'' && top != ''['')) {\n                return false;\n            }\n        }\n    }\n    return st.empty();      // 栈为空则说明所有括号匹配成功\n}\n```", "options": [{"label": "A", "text": "top = st.top(); st.pop();"}, {"label": "B", "text": "st.pop(); top = st.top();"}, {"label": "C", "text": "st.pop(); top = st.front();"}, {"label": "D", "text": "top = st.front(); st.pop();"}]}', '{"correctIndex": 0}', NULL, '["栈", "括号匹配", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C05', 'choice', '{"stem": "下面代码判断队列的第一个元素是否等于a，并删除该元素，横线上应填写（ ）。\n```cpp\n#include <iostream>\n#include <queue>\nusing namespace std;\nbool is_front_equal(std::queue<int>& q, int a) {\n    bool is_equal = false;\n    if (!q.empty()) {\n        ________\n    }\n    return is_equal;\n}\n```", "options": [{"label": "A", "text": "is_equal = (q.front() == a);"}, {"label": "B", "text": "is_equal = (q.front() == a); q.pop();"}, {"label": "C", "text": "q.pop(); is_equal = (q.front() == a);"}, {"label": "D", "text": "q.pop(); is_equal = (q.top() == a);"}]}', '{"correctIndex": 1}', NULL, '["队列", "数据结构", "OCR修复", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C06', 'choice', '{"stem": "假设字母表{a,b,c,d,e} 在字符串出现的频率分别为 10%，15%，30%，16%，29%。若使用哈夫曼编码方式对字母进行二进制编码，则字符abcdef 分别对应的一组哈夫曼编码的长度分别为（  ）。", "options": [{"label": "A", "text": "4, 4, 1, 3, 2"}, {"label": "B", "text": "3, 3, 2, 2, 2"}, {"label": "C", "text": "3, 3, 1, 2, 1"}, {"label": "D", "text": "4, 4, 1, 2, 2"}]}', '{"correctIndex": 1}', NULL, '["哈夫曼编码", "贪心算法", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C07', 'choice', '{"stem": "以下C++代码实现n位的格雷码，则横线上应填写（ ）。\n```cpp\n#include <iostream>\n#include <vector>\n#include <string>\nusing namespace std;\nvector<string> generate_graycode(int n) {\n    vector<string> graycode_list;\n    if (n <= 0) return graycode_list;\n    graycode_list.push_back(\"0\");\n    graycode_list.push_back(\"1\");\n    for (int i = 2; i <= n; i++) {\n        int size = graycode_list.size();\n        for (int j = size - 1; j >= 0; j--) {\n            ________\n        }\n        for (int j = 0; j < size; j++) {\n            graycode_list[j] = \"0\" + graycode_list[j];\n        }\n    }\n    return graycode_list;\n}\n```", "options": [{"label": "A", "text": "graycode_list.push_back(\"0\" + graycode_list[j]);"}, {"label": "B", "text": "graycode_list[j] = \"0\" + graycode_list[j];"}, {"label": "C", "text": "graycode_list.push_back(\"1\" + graycode_list[j]);"}, {"label": "D", "text": "graycode_list[j] = \"1\" + graycode_list[j];"}]}', '{"correctIndex": 1}', NULL, '["格雷码", "算法", "OCR修复", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C08', 'choice', '{"stem": "给定一棵二叉树，其前序遍历结果为：ABDECFG,中序遍历结果为：DEBACFG，则这棵树的正确后序遍历结果是（ ）。", "options": [{"label": "A", "text": "EDBGFCA"}, {"label": "B", "text": "EDGBFCA"}, {"label": "C", "text": "DEBGFCA"}, {"label": "D", "text": "DBEGFCA"}]}', '{"correctIndex": 0}', NULL, '["二叉树", "树的遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C09', 'choice', '{"stem": "一棵有n个结点的完全二叉树用数组进行存储与表示，已知根结点存储在数组的第1个位置。若存储在数组第9个位置的结点存在兄弟结点和两个子结点，则它的兄弟结点和右子结点的位置分别是（ ）。", "options": [{"label": "A", "text": "8, 18"}, {"label": "B", "text": "10, 18"}, {"label": "C", "text": "8, 19"}, {"label": "D", "text": "10, 19"}]}', '{"correctIndex": 2}', NULL, '["二叉树", "完全二叉树", "数组存储", "OCR修复", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C10', 'choice', '{"stem": "二叉树的深度定义为从根结点到叶结点的最长路径上的结点数，则以下基于二叉树的深度优先搜索实现的深度计算函数中横线上应填写（  ）。\n```cpp\n// 定义二叉树的结点结构\nstruct tree_node {\n    int val;\n    tree_node* left;\n    tree_node* right;\n    tree_node(int x) : val(x), left(nullptr), right(nullptr) {}\n};\n// 计算二叉树的深度\nint max_depth(tree_node* root) {\n    if (root == nullptr) {\n        return 0;  // 如果根结点为空，则深度为 0\n    }\n    int left_depth = max_depth(root->left);\n    int right_depth = max_depth(root->right);\n    ———————————————————————— // 在此处填入代码\n}\n```", "options": [{"label": "A", "text": "return left_depth + right_depth;"}, {"label": "B", "text": "return max(left_depth, right_depth);"}, {"label": "C", "text": "return max(left_depth, right_depth) + 1;"}, {"label": "D", "text": "return left_depth + right_depth + 1;"}]}', '{"correctIndex": 2}', NULL, '["二叉树", "深度优先搜索", "递归", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C11', 'choice', '{"stem": "上一题的二叉树深度计算还可以采用二叉树的广度优先搜索来实现。以下基于二叉树的广度优先搜索实现的深度计算函数中横线上应填写（  ）。\n```cpp\n#include <queue>\nint max_depth_bfs(tree_node* root) {\n    if (root == nullptr) {\n        return 0; // 如果树为空，深度为 0\n    }\n    queue <tree_node*> q;\n    q.push(root);\n    int depth = 0;\n    // 使用队列进行层序遍历\n    while (!q.empty()) {\n        ———————————————————————— // 在此处填入代码\n        for (int i = 0; i < level_size; ++i) {\n            tree_node* node = q.front();\n            q.pop();\n            if (node->left) {\n                q.push(node->left);\n            }\n            if (node->right) {\n                q.push(node->right);\n            }\n        }\n    }\n    return depth;\n}\n```", "options": [{"label": "A", "text": "int level_size = q.size(); depth++;"}, {"label": "B", "text": "int level_size = 2; depth++;"}, {"label": "C", "text": "int level_size = q.size(); depth += level_size;"}, {"label": "D", "text": "int level_size = 2; depth += level_size;"}]}', '{"correctIndex": 0}', NULL, '["二叉树", "广度优先搜索", "层序遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C12', 'choice', '{"stem": "二叉搜索树中的每个结点，其左子树的所有结点值都小于该结点值，右子树的所有结点值都大于该结点值。以下代码对给定的整数数组(假设数组中没有数值相等的元素)，构造一个对应的二叉搜索树，横线上应填写（  ）:\n```cpp\n// 定义二叉树的结点结构\nstruct tree_node {\n    int val;\n    tree_node* left;\n    tree_node* right;\n    tree_node(int x) : val(x), left(nullptr), right(nullptr) {}\n};\n// 插入结点到二叉搜索树中\ntree_node* insert(tree_node* root, int val) {\n    if (root == nullptr) {\n        return new tree_node(val);\n    }\n    ———————————————————————— // 在此处填入代码\n    return root;\n}\n// 根据给定数组构造二叉搜索树\ntree_node* constructBST(const int arr[], int size) {\n    tree_node* root = nullptr;\n    for (int i = 0; i < size; ++i) {\n        root = insert(root, arr[i]);\n    }\n    return root;\n}\n```", "options": [{"label": "A", "text": "if (val < root->val)\n  root->left = insert(root->left, val);\nelse\n  root->right = insert(root->right, val);"}, {"label": "B", "text": "if (val > root->val)\n  root->left = insert(root->left, val);\nelse\n  root->right = insert(root->right, val);"}, {"label": "C", "text": "if (val < root->val)\n  root->left = insert(root, val);\nelse\n  root->right = insert(root, val);"}, {"label": "D", "text": "if (val > root->val)\n  root->left = insert(root, val);\nelse\n  root->right = insert(root, val);"}]}', '{"correctIndex": 0}', NULL, '["二叉搜索树", "递归", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C13', 'choice', '{"stem": "对上题中的二叉搜索树，当输入数组为[5,3,7,2,4,6,8]时，构建二叉搜索树，并采用如下代码实现的遍历方式，得到的输出是（ ）。\n```cpp\nvoid traversal(tree_node* root) {\n    if (root == nullptr) return;\n    traversal(root->left);\n    cout << root->val << \" \";\n    traversal(root->right);\n}\n```", "options": [{"label": "A", "text": "5 3 7 2 4 6 8"}, {"label": "B", "text": "2 3 4 5 6 7 8"}, {"label": "C", "text": "2 4 3 6 8 7 5"}, {"label": "D", "text": "2 4 3 5 6 7 8"}]}', '{"correctIndex": 1}', NULL, '["二叉搜索树", "中序遍历", "OCR修复", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C14', 'choice', '{"stem": "动态规划通常用于解决（  ）。", "options": [{"label": "A", "text": "无法分解的问题"}, {"label": "B", "text": "可以分解成相互依赖的子问题的问题"}, {"label": "C", "text": "可以通过贪心算法解决的问题"}, {"label": "D", "text": "只能通过递归解决的问题"}]}', '{"correctIndex": 1}', NULL, '["动态规划", "算法思想", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-C15', 'choice', '{"stem": "阅读以下用动态规划解决的0-1背包问题的函数，假设背包的容量W是10kg，假设输入4个物品的重量weights分别为1,3,4,6（单位为kg），每个物品对应的价值values分别为20,30,50,60，则函数的输出为（ ）。\n```cpp\nint knapsack(int W, const vector<int>& weights, const vector<int>& values, int n) {\n    vector<vector<int>> dp(n + 1, vector<int>(W + 1, 0));\n    for (int i = 1; i <= n; ++i) {\n        for (int w = 0; w <= W; ++w) {\n            if (weights[i-1] <= w)\n                dp[i][w] = max(dp[i-1][w], dp[i-1][w-weights[i-1]] + values[i-1]);\n            else\n                dp[i][w] = dp[i-1][w];\n        }\n    }\n    return dp[n][W];\n}\n```", "options": [{"label": "A", "text": "90"}, {"label": "B", "text": "100"}, {"label": "C", "text": "110"}, {"label": "D", "text": "140"}]}', '{"correctIndex": 2}', NULL, '["动态规划", "0-1背包", "OCR修复", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-J01', 'judgment', '{"stem": "C++、Python和JAVA等都是面向对象的编程语言。"}', '{"correct": true}', NULL, '["编程语言", "面向对象", "GESP-6"]', 4, 1775530000000);
