INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-J03', 'judgment', '{"stem": "栈是一种线性结构，可通过数组或链表来实现。二者相比，数组实现占用的内存较少，链表实现的入队和出队操作的时间复杂度较低。"}', '{"correct": false}', NULL, '["栈", "数据结构", "时间复杂度", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-J04', 'judgment', '{"stem": "运行以下C++代码，屏幕将输出\"derived class\"。\n```cpp\n#include <iostream>\nusing namespace std;\nclass base {\npublic:\n    virtual void show() {\n        cout << \"base class\" << endl;\n    }\n};\nclass derived : public base {\npublic:\n    void show() override {\n        cout << \"derived class\" << endl;\n    }\n};\nint main() {\n    base* b;\n    derived d;\n    b = &d;\n    b->show();\n    return 0;\n}\n```"}', '{"correct": true}', NULL, '["面向对象", "虚函数", "多态", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202409-J05', 'judgment', '{"stem": "如下列代码所示的基类（base）及其派生类（derived），则生成一个派生类的对象时，只调用派生类的构造函数。\n```cpp\n#include <iostream>\nusing namespace std;\nclass base {\npublic:\n    base() {\n        cout << \"base constructor\" << endl;\n    }\n    ~base() {\n        cout << \"base destructor\" << endl;\n    }\n};\nclass derived : public base {\n public:\n    derived() {\n        cout << \"derived constructor\" << endl;\n    }\n    ~derived() {\n        cout << \"derived destructor\" << endl;\n    }\n};\n```"}', '{"correct": false}', NULL, '["面向对象", "继承", "构造函数", "GESP-6"]', 4, 1775530000000);
