INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C02', 'choice', '{"stem": "以下关于C++中类的说法，哪一项是正确的？", "options": [{"label": "A", "text": "类中定义的所有成员变量和成员函数默认是public 访问权限。"}, {"label": "B", "text": "类的构造函数必须显式声明返回类型为void 。"}, {"label": "C", "text": "在C++中，类的数据一般设置为私有，其公有成员函数提供访问私有数据的唯一途径。"}, {"label": "D", "text": "同一个类的实例有各自的成员数据和成员函数。"}]}', '{"correctIndex": 2}', NULL, '["面向对象", "类", "访问权限", "封装", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C03', 'choice', '{"stem": "以下C++代码段中存在语法错误或逻辑错误，（  ）是正确的。\n\n#include <iostream>\nusing namespace std;\nclass MyClass {\npublic:\n    MyClass() {\n        cout << \"Constructor called!\" << endl;\n    }\n    void display() {\n        cout << \"Display function called!\" << endl;\n    }\n};\nint main() {\n    MyClass* obj = NULL;\n    obj->display();\n    return 0;\n}", "options": [{"label": "A", "text": "NULL  在C++中无法用于指针初始化，应使用 nullptr 。"}, {"label": "B", "text": "obj  的定义应该是 MyClass obj;  而不是指针类型。"}, {"label": "C", "text": "obj->display()  语句存在空指针访问错误，obj  应该初始化为一个有效的对象。"}, {"label": "D", "text": "obj->display()  语句会调用 display()  函数，但它没有输出任何内容。"}]}', '{"correctIndex": 2}', NULL, '["指针", "空指针", "对象初始化", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C04', 'choice', '{"stem": "阅读以下代码，下面哪一项是正确的？\n\nvoid processData() {\n    stack<int> s;\n    queue<int> q;\n    for (int i = 1; i <= 5; ++i) {\n        s.push(i);\n        q.push(i);\n    }\n    while (!s.empty()) {\n        cout << \"Stack pop: \" << s.top() << endl;\n        s.pop();\n    }\n    while (!q.empty()) {\n        cout << \"Queue pop: \" << q.front() << endl;\n        q.pop();\n    }\n}", "options": [{"label": "A", "text": "栈s 的输出顺序是 1 2 3 4 5 ，队列q 的输出顺序是 5 4 3 2 1 。"}, {"label": "B", "text": "栈s 的输出顺序是 5 4 3 2 1 ，队列q 的输出顺序是 1 2 3 4 5 。"}, {"label": "C", "text": "栈s 的输出顺序是 1 2 3 4 5 ，队列q 的输出顺序是 1 2 3 4 5 。"}, {"label": "D", "text": "栈s 的输出顺序是 1 2 3 4 5 ，队列q 的输出顺序是 1 2 3 4 5 ，程序不会正常执行。"}]}', '{"correctIndex": 1}', NULL, '["栈与队列", "数据结构", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C05', 'choice', '{"stem": "n个节点的双向循环链，在其中查找某个节点的平均时间复杂度是( )。", "options": [{"label": "A", "text": "O(1)"}, {"label": "B", "text": "O(n)"}, {"label": "C", "text": "O(log n)"}, {"label": "D", "text": "O(n²)"}]}', '{"correctIndex": 1}', NULL, '["链表", "时间复杂度", "双向循环链表", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C06', 'choice', '{"stem": "以下关于树的说法，（  ）是正确的。", "options": [{"label": "A", "text": "在⼀棵⼆叉树中，叶⼦结点的度⼀定是2。"}, {"label": "B", "text": "满⼆叉树中每⼀层的结点数等于2^层数。"}, {"label": "C", "text": "在⼀棵树中，所有结点的度之和等于所有叶⼦结点的度之和。"}, {"label": "D", "text": "⼀棵⼆叉树的先序遍历结果和中序遍历结果⼀定相同。"}]}', '{"correctIndex": 1}', NULL, '["二叉树", "树的性质", "满二叉树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C07', 'choice', '{"stem": "已知字符集 {A, B, C, D}  的出现频率如下表所示：\n\n字符 | 频率\nA    | 8\nB    | 3\nC    | 1\nD    | 6\n\n根据哈夫曼编码法，下面（   ）是正确的哈夫曼树。", "options": [{"label": "A", "text": "[图片：ABCD根节点，左子A，右子BCD，BCD左子D，右子BC，BC左子B右子C]"}, {"label": "B", "text": "[图片：ABCD根节点，左子A，右子BCD，BCD左子B，右子CD，CD左子C右子D]"}, {"label": "C", "text": "[图片：ABCD根节点，左子D，右子ABC，ABC左子A，右子BC，BC左子B右子C]"}, {"label": "D", "text": "[图片：ABCD根节点，左子C，右子ABC，ABC左子B，右子AD，AD左子A右子D]"}]}', '{"correctIndex": 0}', NULL, '["哈夫曼编码", "哈夫曼树", "贪心算法", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C08', 'choice', '{"stem": "上一题中各字符的哈夫曼编码是（  ）。", "options": [{"label": "A", "text": "A: 0, B: 10, C: 110, D: 111"}, {"label": "B", "text": "A: 0, B: 10, C: 11, D: 10"}, {"label": "C", "text": "A: 0, B: 101, C: 100, D: 11"}, {"label": "D", "text": "A: 11, B: 10, C: 01, D: 00"}]}', '{"correctIndex": 2}', NULL, '["哈夫曼编码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C09', 'choice', '{"stem": "(  )是3位格雷编码。", "options": [{"label": "A", "text": "000 001 011 010 110 111 101 100"}, {"label": "B", "text": "000 001 010 011 100 101 110 111"}, {"label": "C", "text": "000 001 100 101 011 010 111 110"}, {"label": "D", "text": "000 010 001 011 100 110 101 111"}]}', '{"correctIndex": 0}', NULL, '["格雷码", "编码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C10', 'choice', '{"stem": "根据下面二叉树和给定的代码，\n\n[图片：二叉搜索树，根节点5，左子树3(左2右4)，右子树7(左6右8)]\n\n给定以下二叉搜索树，调用函数 search(root,7)  时，输出的结果是（  ）。\n\n#include <iostream>\nusing namespace std;\nstruct TreeNode {\n    int val;\n    TreeNode* left;\n    TreeNode* right;\n    TreeNode(int x) : val(x), left(NULL), right(NULL) {}\n};\nTreeNode* search(TreeNode* root, int val) {\n    cout << root->val << \" \";\n    if (root == NULL || root->val == val) return root;\n    if (val < root->val)\n        return search(root->left, val);\n    else\n        return search(root->right, val);\n}", "options": [{"label": "A", "text": "5 7"}, {"label": "B", "text": "5 3 7"}, {"label": "C", "text": "5 7 6"}, {"label": "D", "text": "5 3 4 7"}]}', '{"correctIndex": 0}', NULL, '["二叉搜索树", "递归", "树的搜索", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C11', 'choice', '{"stem": "阅读以下二叉树的深度优先搜索算法，横线上应填写（   ）。\n\nvoid dfs(TreeNode* root) {\n    if (root == nullptr)\n        return;\n    stack<TreeNode*> s;\n    s.push(root);\n    while (!s.empty()) {\n        ———————————————————————— // 在此处填入代码\n        cout << node->value << \" \";\n        if (node->right) s.push(node->right);\n        if (node->left) s.push(node->left);\n    }\n}", "options": [{"label": "A", "text": "TreeNode* node = s.top();"}, {"label": "B", "text": "TreeNode* node = s.top();  s.pop();"}, {"label": "C", "text": "TreeNode* node = s.front();"}, {"label": "D", "text": "TreeNode* node = s.front();  s.pop();"}]}', '{"correctIndex": 1}', NULL, '["深度优先搜索", "DFS", "栈", "二叉树遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C12', 'choice', '{"stem": "阅读以下二叉树的广度优先搜索的代码，横线上应填写（   ）。\n\n#include <queue>\nvoid bfs(TreeNode* root) {\n    if (root == NULL) return;\n    queue<TreeNode*> q;\n    q.push(root);\n    while (!q.empty()) {\n        ———————————————————————— // 在此处填入代码\n        cout << node->val << \" \";\n        if (node->left) {\n            q.push(node->left);\n        }\n        if (node->right) {\n            q.push(node->right);\n        }\n    }\n}", "options": [{"label": "A", "text": "TreeNode* node = q.top();"}, {"label": "B", "text": "TreeNode* node = q.top();  q.pop();"}, {"label": "C", "text": "TreeNode* node = q.front();"}, {"label": "D", "text": "TreeNode* node = q.front();  q.pop();"}]}', '{"correctIndex": 3}', NULL, '["广度优先搜索", "BFS", "队列", "二叉树遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C13', 'choice', '{"stem": "使用上题中的宽度优先搜索算法遍历以下这棵树，可能的输出是( )。\n\n[图片：二叉树，根节点1，左子树2(左8右9，9有左4右5)，右子树3(右6，6有右7)]", "options": [{"label": "A", "text": "1 2 3 8 9 6 4 5 7"}, {"label": "B", "text": "1 3 2 6 9 8 7 5 4"}, {"label": "C", "text": "1 2 3 8 9 6 4 5 7"}, {"label": "D", "text": "1 2 8 9 3 4 5 6 7"}]}', '{"correctIndex": 2}', NULL, '["广度优先搜索", "BFS", "二叉树遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C14', 'choice', '{"stem": "以下关于动态规划的描述，（  ）是正确的。", "options": [{"label": "A", "text": "动态规划适用于没有重叠子问题的优化问题。"}, {"label": "B", "text": "动态规划要求问题具有最优子结构和无后效性。"}, {"label": "C", "text": "动态规划通常通过递归来实现。"}, {"label": "D", "text": "动态规划与贪心算法不同，贪心算法不适用于有重叠子问题的问题。"}]}', '{"correctIndex": 1}', NULL, '["动态规划", "算法特性", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-C15', 'choice', '{"stem": "假设背包的最大容量W=10，共有4个物品可供选择，4个物品的重量分别为{2, 3, 4, 5}，对应的价值分别为{30, 40, 50, 60}，则该0/1背包问题中，背包的最大价值为（  ）。", "options": [{"label": "A", "text": "70"}, {"label": "B", "text": "90"}, {"label": "C", "text": "100"}, {"label": "D", "text": "120"}]}', '{"correctIndex": 2}', NULL, '["动态规划", "背包问题", "0/1背包", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J01', 'judgment', '{"stem": "构造函数是一种特殊的类成员函数，构造函数的名称和类名相同。但通过函数重载，可以创建多个同名的构造函数，条件是每个构造函数的参数列表不同。"}', '{"correct": true}', NULL, '["面向对象", "构造函数", "函数重载", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J02', 'judgment', '{"stem": "类的静态成员函数既能访问类的静态数据成员，也能访问非静态数据成员。"}', '{"correct": false}', NULL, '["面向对象", "静态成员函数", "类", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J03', 'judgment', '{"stem": "栈中元素的插入和删除操作都在栈的顶端进行，所以方便用单向链表实现。"}', '{"correct": true}', NULL, '["栈", "链表", "数据结构", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J04', 'judgment', '{"stem": "下面代码构建的树一定是完全二叉树：\n\nstruct TreeNode {\n    int value;\n    TreeNode* left;\n    TreeNode* right;\n};\nTreeNode* buildCompleteBinaryTree() {\n    TreeNode* root = new TreeNode{1};\n    root->left = new TreeNode{2};\n    root->right = new TreeNode{3};\n    root->left->left = new TreeNode{4};\n    root->left->right = new TreeNode{5};\n    root->right->left = new TreeNode{6};\n    return root;\n}"}', '{"correct": true}', NULL, '["二叉树", "完全二叉树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J05', 'judgment', '{"stem": "在二叉排序树中，左子树所有节点的值都大于根节点的值，右子树所有节点的值都小于根节点的值。"}', '{"correct": false}', NULL, '["二叉排序树", "二叉搜索树", "树的性质", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J06', 'judgment', '{"stem": "在生成一个派生类的对象时，只调用派生类的构造函数。"}', '{"correct": false}', NULL, '["面向对象", "继承", "构造函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J07', 'judgment', '{"stem": "下面的代码实现了二叉树的前序遍历，它通过递归方法访问每个节点并打印节点值。\n\nvoid preorder(TreeNode* root) {\n    if (root == NULL) return;\n    cout << root->val << \" \";\n    preorder(root->left);\n    preorder(root->right);\n}"}', '{"correct": true}', NULL, '["二叉树", "前序遍历", "递归", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J08', 'judgment', '{"stem": "在⼆叉树中，宽度优先搜索算法（BFS）保证从起点到每个节点的访问路径是边数最少的路径（即最短路径）。"}', '{"correct": true}', NULL, '["广度优先搜索", "BFS", "最短路径", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J09', 'judgment', '{"stem": "在解决简单背包问题时，动态规划的状态转移⽅程如下：\n\ndp[i][w] = max(dp[i-1][w], dp[i-1][w - weights[i-1]] + values[i-1]);\n\n该方程表示：在考虑第 i  个物品时，当前背包容量为 w ，如果不放物品 i ，则最大价值是 dp[i-1][w] ；如果放入物品 i ，则最大价值是 dp[i-1][w - weights[i-1]] + values[i-1] ，其中数组weights 和values 分别表示所有物品的重量和价值，数组下标从0 开始。"}', '{"correct": true}', NULL, '["动态规划", "背包问题", "状态转移方程", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202412-J10', 'judgment', '{"stem": "栈中元素的插入和删除操作都在栈的顶端进行，所以方便用双向链表比单向链表更合适表实现。"}', '{"correct": false}', NULL, '["栈", "链表", "数据结构", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C01', 'choice', '{"stem": "下列关于类的说法，错误的是( )。", "options": [{"label": "A", "text": "构造函数不能声明为虚函数，但析构函数可以。"}, {"label": "B", "text": "函数参数如声明为类的引用类型，调用时不会调用该类的复制构造函数。"}, {"label": "C", "text": "静态方法属于类而不是某个具体对象，因此推荐用 类名::方法(...)  调用。"}, {"label": "D", "text": "不管基类的析构函数是否是虚函数，都可以通过基类指针/引用正确删除派生类对象。"}]}', '{"correctIndex": 3}', NULL, '["面向对象", "继承与多态", "虚函数", "析构函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C02', 'choice', '{"stem": "假设变量veh 是类Car 的一个实例，我们可以调用veh.move() ，是因为面向对象编程有（   ）性质。\n\nclass Vehicle {\nprivate:\n    string brand;   \npublic:\n    Vehicle(string b) : brand(b) {}\n    void setBrand(const string& b) { brand = b; }  \n    string getBrand() const { return brand; }\n    void move() const {                   \n        cout << brand << \" is moving...\" << endl;\n    }\n};\nclass Car : public Vehicle {\nprivate:\n    int seatCount;\npublic:\n    Car(string b, int seats) : Vehicle(b), seatCount(seats) {}\n    void showInfo() const {\n        cout << \"This car is a \" << getBrand()\n             << \" with \" << seatCount << \" seats.\" << endl;\n    }\n};", "options": [{"label": "A", "text": "继承 (Inheritance)"}, {"label": "B", "text": "封装 (Encapsulation)"}, {"label": "C", "text": "多态 (Polymorphism)"}, {"label": "D", "text": "链接 (Linking)"}]}', '{"correctIndex": 0}', NULL, '["面向对象", "继承与多态", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C03', 'choice', '{"stem": "下面代码中v1 和v2 调用了相同接口 move() ，但输出结果不同，这体现了面向对象编程的（   ）特性。\n\nclass Vehicle {\nprivate:\n    string brand;   \npublic:\n    Vehicle(string b) : brand(b) {}\n    void setBrand(const string& b) { brand = b; }  \n    string getBrand() const { return brand; }\n    virtual void move() const {                   \n        cout << brand << \" is moving...\" << endl;\n    }\n};\nclass Car : public Vehicle {\nprivate:\n    int seatCount;\npublic:\n    Car(string b, int seats) : Vehicle(b), seatCount(seats) {}\n    void showInfo() const {\n        cout << \"This car is a \" << getBrand()\n             << \" with \" << seatCount << \" seats.\" << endl;\n    }\n    void move() const override {\n        cout << getBrand() << \" car is driving on the road!\" << endl;\n    }\n};\nclass Bike : public Vehicle {\npublic:\n    Bike(string b) : Vehicle(b) {}\n    void move() const override {\n        cout << getBrand() << \" bike is cycling on the path!\" << endl;\n    }\n};\nint main() {\n    Vehicle* v1 = new Car(\"Toyota\", 5);\n    Vehicle* v2 = new Bike(\"Giant\");\n    v1->move();  \n    v2->move();  \n    delete v1;\n    delete v2;\n    return 0;\n}", "options": [{"label": "A", "text": "继承 (Inheritance)"}, {"label": "B", "text": "封装 (Encapsulation)"}, {"label": "C", "text": "多态 (Polymorphism)"}, {"label": "D", "text": "链接 (Linking)"}]}', '{"correctIndex": 2}', NULL, '["面向对象", "继承与多态", "虚函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C04', 'choice', '{"stem": "栈的操作特点是（   ）。", "options": [{"label": "A", "text": "先进先出"}, {"label": "B", "text": "先进后出"}, {"label": "C", "text": "随机访问"}, {"label": "D", "text": "双端进出"}]}', '{"correctIndex": 1}', NULL, '["栈与队列", "数据结构", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C05', 'choice', '{"stem": "循环队列常用于实现数据缓冲。假设一个循环队列容量为 5 （即最多存放 4  个元素，留一个位置区分空与满），依次进行操作：入队数据1，2，3，出队1个数据，再入队数据4和5，此时队首到队尾的元素顺序是（   ）。", "options": [{"label": "A", "text": "[2, 3, 4, 5]"}, {"label": "B", "text": "[1, 2, 3, 4]"}, {"label": "C", "text": "[3, 4, 5, 2]"}, {"label": "D", "text": "[2, 3, 5, 4]"}]}', '{"correctIndex": 0}', NULL, '["栈与队列", "循环队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C06', 'choice', '{"stem": "以下函数createTree() 构造的树是什么类型？\n\nstruct TreeNode {\n    int val;\n    TreeNode* left;\n    TreeNode* right;\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n};\nTreeNode* createTree() {\n    TreeNode* root = new TreeNode(1);\n    root->left = new TreeNode(2);\n    root->right = new TreeNode(3);\n    root->left->left = new TreeNode(4);\n    root->left->right = new TreeNode(5);\n    return root;\n}", "options": [{"label": "A", "text": "满二叉树"}, {"label": "B", "text": "完全二叉树"}, {"label": "C", "text": "二叉排序树"}, {"label": "D", "text": "其他都不对"}]}', '{"correctIndex": 1}', NULL, '["二叉树", "完全二叉树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C07', 'choice', '{"stem": "已知二叉树的 中序遍历 是 [D, B, E, A, F, C]，先序遍历 是 [A, B, D, E, C, F]。请问该二叉树的后序遍历结果是（   ）。", "options": [{"label": "A", "text": "[D, E, B, F, C, A]"}, {"label": "B", "text": "[D, B, E, F, C, A]"}, {"label": "C", "text": "[D, E, B, C, F, A]"}, {"label": "D", "text": "[B, D, E, F, C, A]"}]}', '{"correctIndex": 0}', NULL, '["二叉树", "树的遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C08', 'choice', '{"stem": "完全二叉树可以用数组连续高效存储，如果节点从1 开始编号，则对有两个孩子节点的节点i ，（  ）。", "options": [{"label": "A", "text": "左孩子位于2i ，右孩子位于2i+1"}, {"label": "B", "text": "完全二叉树的叶子节点可以出现在最后一层的任意位置"}, {"label": "C", "text": "所有节点都有两个孩子"}, {"label": "D", "text": "左孩子位于2i+1 ，右孩子位于2i+2"}]}', '{"correctIndex": 0}', NULL, '["二叉树", "完全二叉树", "数组存储", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C09', 'choice', '{"stem": "设有字符集{a, b, c, d, e, f} ，其出现频率分别为 {5, 9, 12, 13, 16, 45} 。哈夫曼算法构造最优前缀编码，以下哪一组可能是对应的哈夫曼编码？（非叶子节点左边分支记作 0，右边分支记作 1，左右互换不影响正确性）。", "options": [{"label": "A", "text": "a: 00；b: 01；c: 10；d: 110；e: 111；f: 0"}, {"label": "B", "text": "a: 1100；b: 1101；c: 100；d: 101；e: 111；f: 0"}, {"label": "C", "text": "a: 000；b: 001；c: 01；d: 10；e: 110；f: 111"}, {"label": "D", "text": "a: 10；b: 01；c: 100；d: 101；e: 111；f: 0"}]}', '{"correctIndex": 1}', NULL, '["哈夫曼编码", "贪心算法", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C10', 'choice', '{"stem": "下面代码生成格雷编码，则横线上应填写（   ）。\n\nvector<string> grayCode(int n) {\n    if (n == 0) return {\"0\"};\n    if (n == 1) return {\"0\", \"1\"};\n    vector<string> prev = grayCode(n-1);\n    vector<string> result;\n    for (string s : prev) {\n        result.push_back(\"0\" + s);\n    }\n    for (_______________) {  // 在此处填写代码\n        result.push_back(\"1\" + prev[i]);\n    }\n    return result;\n}", "options": [{"label": "A", "text": "int i = 0; i < prev.size(); i++"}, {"label": "B", "text": "int i = prev.size()-1; i >= 0; i--"}, {"label": "C", "text": "auto s : prev"}, {"label": "D", "text": "int i = prev.size()/2; i < prev.size(); i++"}]}', '{"correctIndex": 1}', NULL, '["格雷码", "递归算法", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C11', 'choice', '{"stem": "请将下列树的深度优先遍历代码补充完整，横线处应填入（   ）。\n\nstruct TreeNode {\n    int val;\n    TreeNode* left;\n    TreeNode* right;\n    TreeNode(int x): val(x), left(nullptr), right(nullptr) {}\n};\nvoid dfs(TreeNode* root) {\n    if (!root) return;\n    ______<TreeNode*> temp;     // 在此处填写代码\n    temp.push(root);\n    while (!temp.empty()) {\n        TreeNode* node = temp.top();\n        temp.pop();\n        cout << node->val << \" \";\n        if (node->right) temp.push(node->right);\n        if (node->left) temp.push(node->left);\n    }\n}", "options": [{"label": "A", "text": "vector"}, {"label": "B", "text": "list"}, {"label": "C", "text": "queue"}, {"label": "D", "text": "stack"}]}', '{"correctIndex": 3}', NULL, '["二叉树", "深度优先遍历", "栈与队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C12', 'choice', '{"stem": "令 n 是树的节点数目，下列代码实现了树的广度优先遍历，其时间复杂度是（   ）。\n\nvoid bfs(TreeNode* root) {\n    if (!root) return;\n    queue<TreeNode*> q;\n    q.push(root);\n    while (!q.empty()) {\n        TreeNode* node = q.front();\n        q.pop();\n        cout << node->val << \" \";\n        if (node->left) q.push(node->left);\n        if (node->right) q.push(node->right);\n    }\n}", "options": [{"label": "A", "text": "O(n)"}, {"label": "B", "text": "O(n²)"}, {"label": "C", "text": "O(log n)"}, {"label": "D", "text": "O(n log n)"}]}', '{"correctIndex": 0}', NULL, '["二叉树", "广度优先遍历", "时间复杂度", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C13', 'choice', '{"stem": "在二叉排序树（Binary Search Tree, BST）中查找元素 50 ，从根节点开始：若根值为 60 ，则下一步应去搜索：", "options": [{"label": "A", "text": "左子树"}, {"label": "B", "text": "右子树"}, {"label": "C", "text": "随机"}, {"label": "D", "text": "根节点"}]}', '{"correctIndex": 0}', NULL, '["二叉排序树", "搜索算法", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C14', 'choice', '{"stem": "删除二叉排序树中的节点时，如果节点有两个孩子，则横线处应填入（   ），其中findMax 和findMin 分别为寻找树的最大值和最小值的函数。\n\nstruct TreeNode {\n    int val;\n    TreeNode* left;\n    TreeNode* right;\n    TreeNode(int x): val(x), left(nullptr), right(nullptr) {}\n};\nTreeNode* deleteNode(TreeNode* root, int key) {\n    if (!root) return nullptr;\n    if (key < root->val) {\n        root->left = deleteNode(root->left, key);\n    }\n    else if (key > root->val) {\n        root->right = deleteNode(root->right, key);\n    }\n    else {\n        if (!root->left) return root->right;\n        if (!root->right) return root->left;\n        TreeNode* temp = ____________;          // 在此处填写代码\n        root->val = temp->val;\n        root->right = deleteNode(root->right, temp->val);\n    }\n    return root;\n}", "options": [{"label": "A", "text": "root->left"}, {"label": "B", "text": "root->right"}, {"label": "C", "text": "findMin(root->right)"}, {"label": "D", "text": "findMax(root->left)"}]}', '{"correctIndex": 2}', NULL, '["二叉排序树", "删除操作", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-C15', 'choice', '{"stem": "给定n个物品和一个最大承重为W的背包，每个物品有一个重量wt和价值val，每个物品只能选择放或不放。目标是选择若干个物品放入背包，使得总价值最大，且总重量不超过W，则横线上应填写（   ）。\n\nint knapsack(int W, vector<int>& wt, vector<int>& val, int n) {\n    vector<int> dp(W+1, 0);\n    for (int i = 0; i < n; ++i) {\n        for (int w = W; w >= wt[i]; --w) {\n            ________________________        // 在此处填写代码\n        }\n    }\n    return dp[W];\n}", "options": [{"label": "A", "text": "dp[w] = max(dp[w], dp[w] + val[i]);"}, {"label": "B", "text": "dp[w] = dp[w - wt[i]] + val[i];"}, {"label": "C", "text": "dp[w] = max(dp[w - 1], dp[w - wt[i]] + val[i]);"}, {"label": "D", "text": "dp[w] = max(dp[w], dp[w - wt[i]] + val[i]);"}]}', '{"correctIndex": 3}', NULL, '["动态规划", "背包问题", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-J01', 'judgment', '{"stem": "当基类可能被多态使用，其析构函数应该声明为虚函数。"}', '{"correct": true}', NULL, '["面向对象", "虚函数", "析构函数", "GESP-6"]', 4, 1775530000000);
