INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-J06', 'judgment', '{"stem": "一棵有 n 个节点的二叉树一定有 n-1 条边。"}', '{"correct": true}', NULL, '["二叉树", "图论", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-J07', 'judgment', '{"stem": "以下代码实现了二叉树的中序遍历。输入以下二叉树，中序遍历结果是4 2 5 1 3 6 。\n\n[图片：二叉树结构]\n//     1\n//    / \\\n//   2   3\n//  / \\   \\\n// 4   5   6\n\nstruct TreeNode {\n    int val;\n    TreeNode* left;\n    TreeNode* right;\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n};\nvoid inorderIterative(TreeNode* root) {\n    stack<TreeNode*> st;\n    TreeNode* curr = root;\n    while (curr || !st.empty()) {\n        while (curr) {\n            st.push(curr);\n            curr = curr->left;\n        }\n        curr = st.top(); st.pop();\n        cout << curr->val << \" \";\n        curr = curr->right;\n    }\n}"}', '{"correct": true}', NULL, '["二叉树", "中序遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-J08', 'judgment', '{"stem": "下面代码实现的二叉排序树的查找操作时间复杂度是 O(h)，其中 h 为树高。\n\nTreeNode* searchBST(TreeNode* root, int val) {\n    while (root && root->val != val) {\n        root = (val < root->val) ? root->left : root->right;\n    }\n    return root;\n}"}', '{"correct": true}', NULL, '["二叉排序树", "时间复杂度", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-J09', 'judgment', '{"stem": "下面代码实现了动态规划版本的斐波那契数列计算，其时间复杂度是 O(n)。\n\nint fib_dp(int n) {\n    if (n <= 1) return n;\n    vector<int> dp(n+1);\n    dp[0] = 0;\n    dp[1] = 1;\n    for (int i = 2; i <= n; i++) {\n        dp[i] = dp[i-1] + dp[i-2];\n    }\n    return dp[n];\n}"}', '{"correct": true}', NULL, '["动态规划", "时间复杂度", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202509-J10', 'judgment', '{"stem": "有一排香蕉，每个香蕉有不同的甜度值。小猴子想吃香蕉，但不能吃相邻的香蕉。以下代码能找到小猴子吃到最甜的香蕉组合。\n\n// bananas：香蕉的甜度\nvoid findSelectedBananas(vector<int>& bananas, vector<int>& dp) {\n    vector<int> selected;\n    int i = bananas.size() - 1;\n    while (i >= 0) {\n        if (i == 0) {\n            selected.push_back(0);\n            break;\n        }\n        if (dp[i] == dp[i-1]) {\n            i--;\n        } else {\n            selected.push_back(i);\n            i -= 2;\n        }\n    }\n    reverse(selected.begin(), selected.end());\n    cout << \"小猴子吃了第: \";\n    for (int idx : selected)\n        cout << idx+1 << \" \";\n    cout << \"个香蕉\" << endl;\n}\nint main() {\n    vector<int> bananas = {1, 2, 3, 1}; // 每个香蕉的甜度\n    vector<int> dp(bananas.size());\n    dp[0] = bananas[0];\n    dp[1] = max(bananas[0], bananas[1]);\n    for (int i = 2; i < bananas.size(); i++) {\n        dp[i] = max(bananas[i] + dp[i-2], dp[i-1]);\n    }\n    findSelectedBananas(bananas, dp);\n    return 0;\n}"}', '{"correct": true}', NULL, '["动态规划", "贪心算法", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C01', 'choice', '{"stem": "在面向对象编程中，下列关于虚函数的描述中，错误的是（ ）。", "options": [{"label": "A", "text": "虚函数用于支持运行时多态"}, {"label": "B", "text": "通过基类指针调用虚函数时，会根据对象实际类型决定调用版本"}, {"label": "C", "text": "构造函数可以声明为虚函数以支持多态"}, {"label": "D", "text": "基类析构函数常声明为虚函数以避免资源泄漏"}]}', '{"correctIndex": 2}', NULL, '["面向对象", "虚函数", "多态", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C02', 'choice', '{"stem": "执行如下代码，会输出 钢琴：叮咚叮咚 和 吉他：咚咚当当。这体现了面向对象编程的（   ）特性。\n[注：此题引用了代码，但OCR文本中代码内容不完整]", "options": [{"label": "A", "text": "继承"}, {"label": "B", "text": "封装"}, {"label": "C", "text": "多态"}, {"label": "D", "text": "链接"}]}', '{"correctIndex": 2}', NULL, '["面向对象", "多态", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C03', 'choice', '{"stem": "关于以下代码，说法正确的是（   ）。\nclass Instrument {\npublic:\n    void play() {\n        cout << \"乐器在演奏声音\" << endl;\n    }\n    virtual ~Instrument() {}\n};\nclass Piano : public Instrument {\npublic:\n    void play() override {\n        cout << \"钢琴：叮咚叮咚\" << endl;\n    }\n};\nclass Guitar : public Instrument {\npublic:\n    void play() override {\n        cout << \"吉他：咚咚当当\" << endl;\n    }\n};\nint main() {\n    Instrument* instruments[2];\n    instruments[0] = new Piano();\n    instruments[1] = new Guitar();\n    for (int i = 0; i < 2; ++i) {\n        instruments[i]->play();\n    }\n    for (int i = 0; i < 2; ++i) {\n        delete instruments[i];\n    }\n    return 0;\n}", "options": [{"label": "A", "text": "执行代码会输出两行，内容分别为：钢琴：叮咚叮咚 和 吉他：咚咚当当"}, {"label": "B", "text": "执行代码会输出两行，内容分别为：乐器在演奏声音 和 乐器在演奏声音"}, {"label": "C", "text": "代码编译出现错误"}, {"label": "D", "text": "代码运行出现错误"}]}', '{"correctIndex": 2}', NULL, '["面向对象", "虚函数", "多态", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C04', 'choice', '{"stem": "某文本编辑器把用户输入的字符依次压入栈 S。用户依次输入 A, B, C, D 后，用户按了两次撤销（每次撤销，弹出栈顶一个字符）。此时栈从栈底到栈顶的内容是：（   ）。", "options": [{"label": "A", "text": "A B"}, {"label": "B", "text": "A B C"}, {"label": "C", "text": "A B D"}, {"label": "D", "text": "B C"}]}', '{"correctIndex": 0}', NULL, '["栈", "数据结构", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C05', 'choice', '{"stem": "假设循环队列数组长度为 N，其中队空判断条件为：front == rear，队满判断条件为：(rear + 1) % N == front，出队对应的操作为：front = (front + 1) % N，入队对于的操作为：rear = (rear + 1) % N。循环队列长度 N = 6，初始 front = 1, rear = 1，执行操作序列为：入队, 入队, 入队, 出队, 入队, 入队，则最终 (front, rear) 的值是（   ）。", "options": [{"label": "A", "text": "(2, 5)"}, {"label": "B", "text": "(2, 0)"}, {"label": "C", "text": "(3, 5)"}, {"label": "D", "text": "(3, 0)"}]}', '{"correctIndex": 1}', NULL, '["队列", "循环队列", "数据结构", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C06', 'choice', '{"stem": "以下函数 check() 用于判断一棵二叉树是否为（   ）。\nbool check(TreeNode* root) {\n    if (!root) return true;\n    queue<TreeNode*> q;\n    q.push(root);\n    bool hasNull = false;\n    while (!q.empty()) {\n        TreeNode* cur = q.front(); q.pop();\n        if (!cur) {\n            hasNull = true;\n        } else {\n            if (hasNull) return false;\n            q.push(cur->left);\n            q.push(cur->right);\n        }\n    }\n    return true;\n}", "options": [{"label": "A", "text": "满二叉树"}, {"label": "B", "text": "完全二叉树"}, {"label": "C", "text": "二叉搜索树"}, {"label": "D", "text": "平衡二叉树"}]}', '{"correctIndex": 1}', NULL, '["二叉树", "完全二叉树", "数据结构", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C07', 'choice', '{"stem": "以下代码实现了二叉树的（  ）。\nvoid traverse(TreeNode* root) {\n    if (!root) return;\n    traverse(root->left);\n    traverse(root->right);\n    cout << root->val << \" \";\n}", "options": [{"label": "A", "text": "前序遍历"}, {"label": "B", "text": "中序遍历"}, {"label": "C", "text": "后序遍历"}, {"label": "D", "text": "层序遍历"}]}', '{"correctIndex": 2}', NULL, '["二叉树", "后序遍历", "树的遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C08', 'choice', '{"stem": "下面代码实现了哈夫曼编码，则横线处应填写的代码是（  ）。\n[代码片段]\nfor (int k = 1; k < n; k++) {\n    int x = PopMinNode(nodes, leafIdx, n, pA, internalIdx, pB);\n    int y = PopMinNode(nodes, leafIdx, n, pA, internalIdx, pB);\n    int z = (int)nodes.size();\n    ________________________\n}", "options": [{"label": "A", "text": "nodes.push_back(Node(nodes[x].w + nodes[y].w, x, y, -1));\ninternalIdx.push_back(z);"}, {"label": "B", "text": "nodes.push_back(Node(nodes[x].w + nodes[y].w, x, y, -1));\nleafIdx.push_back(z);"}, {"label": "C", "text": "internalIdx.push_back(z);\nnodes.push_back(Node(nodes[x].w + nodes[y].w, x, y, x+y));"}, {"label": "D", "text": "nodes.push_back(Node(nodes[x].w + nodes[y].w, x, y, x+y));\nleafIdx.push_back(z);"}]}', '{"correctIndex": 0}', NULL, '["哈夫曼编码", "贪心算法", "数据结构", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C09', 'choice', '{"stem": "以下关于哈夫曼编码的说法，正确的是（  ）。", "options": [{"label": "A", "text": "哈夫曼编码是定长编码"}, {"label": "B", "text": "哈夫曼编码中，没有任何一个字符的编码是另一个字符编码的前缀"}, {"label": "C", "text": "哈夫曼编码一定唯一"}, {"label": "D", "text": "哈夫曼编码不能用于数据压缩"}]}', '{"correctIndex": 1}', NULL, '["哈夫曼编码", "前缀编码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C10', 'choice', '{"stem": "以下函数实现了二叉排序树（BST）的（   ）操作。\nTreeNode* op(TreeNode* root, int x) {\n    if (!root) return new TreeNode(x);\n    if (x < root->val)\n        root->left = op(root->left, x);\n    else\n        root->right = op(root->right, x);\n    return root;\n}", "options": [{"label": "A", "text": "查找"}, {"label": "B", "text": "插入"}, {"label": "C", "text": "删除"}, {"label": "D", "text": "遍历"}]}', '{"correctIndex": 1}', NULL, '["二叉排序树", "BST", "插入操作", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C11', 'choice', '{"stem": "下列代码实现了树的深度优先遍历，则横线处应填入（   ）。\nvoid dfs(TreeNode* root) {\n    if (!root) return;\n    stack<TreeNode*> st;\n    st.push(root);\n    while (!st.empty()) {\n        TreeNode* node = st.top(); st.pop();\n        cout << node->val << \" \";\n        if (node->right) st.push(node->right);\n        ________________________\n    }\n}", "options": [{"label": "A", "text": "if (node->left) st.push(node->left);"}, {"label": "B", "text": "if (node->left) st.pop(node->left);"}, {"label": "C", "text": "if (node->left) st.front(node->left);"}, {"label": "D", "text": "if (node->left) st.push(node->right);"}]}', '{"correctIndex": 0}', NULL, '["深度优先遍历", "DFS", "栈", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C12', 'choice', '{"stem": "给定一棵普通二叉树（节点值没有大小规律），下面代码判断是否存在值为 x 的结点，则横线处应填入（ ）。\nTreeNode* bfsFind(TreeNode* root, int x) {\n    if (!root) return nullptr;\n    queue<TreeNode*> q;\n    q.push(root);\n    while (!q.empty()) {\n        TreeNode* cur = q.front(); q.pop();\n        if (cur->val == x) return cur;\n        ________________________\n    }\n    return nullptr;\n}", "options": [{"label": "A", "text": "q.push(cur);"}, {"label": "B", "text": "if (cur->right) q.push(cur->right);"}, {"label": "C", "text": "if (cur->left)\n    q.push(cur->left);\nif (cur->right)\n    q.push(cur->right);"}, {"label": "D", "text": "q.push(cur->left);\nq.push(cur->right);"}]}', '{"correctIndex": 2}', NULL, '["广度优先遍历", "BFS", "队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C13', 'choice', '{"stem": "在二叉排序树（Binary Search Tree, BST）中，假设节点值互不相同。给定如下搜索函数，以下说法一定正确的是（   ）。\nbool find(Node* root, int x) {\n    while (root) {\n        if (root->val == x) return true;\n        root = (x < root->val) ? root->left : root->right;\n    }\n    return false;\n}", "options": [{"label": "A", "text": "最坏情况下，访问结点数是 [未给出具体数值]"}, {"label": "B", "text": "最坏情况下，访问结点数是 [未给出具体数值]"}, {"label": "C", "text": "无论如何，访问结点数都不超过树高的一半"}, {"label": "D", "text": "一定比在普通二叉树中搜索快"}]}', '{"correctIndex": 1}', NULL, '["二叉排序树", "BST", "搜索算法", "时间复杂度", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C14', 'choice', '{"stem": "0/1 背包（每件物品最多选一次）问题通常可用一维动态规划求解，核心代码如下。则下面说法正确的是（  ）。\nfor each item (w, v):\n    for (int j = W; j >= w; --j)\n        dp[j] = max(dp[j], dp[j-w] + v);", "options": [{"label": "A", "text": "内层 j 必须从小到大，否则会漏解"}, {"label": "B", "text": "内层 j 必须从大到小，否则同一件物品会被用多次"}, {"label": "C", "text": "j 从大到小或从小到大都一样"}, {"label": "D", "text": "只要 dp 初始为 0，方向无所谓"}]}', '{"correctIndex": 1}', NULL, '["动态规划", "0/1背包", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-C15', 'choice', '{"stem": "以下关于动态规划的说法中，错误的是（ ）。", "options": [{"label": "A", "text": "动态规划方法通常能够列出递推公式。"}, {"label": "B", "text": "动态规划方法的时间复杂度通常为状态的个数。"}, {"label": "C", "text": "动态规划方法有递推和递归两种实现形式。"}, {"label": "D", "text": "对很多问题，递推实现和递归实现动态规划方法的时间复杂度相当。"}]}', '{"correctIndex": 1}', NULL, '["动态规划", "时间复杂度", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-J01', 'judgment', '{"stem": "以下代码中，构造函数被调用的次数是1次。\nclass Test {\npublic:\n    Test() { cout << \"T \"; }\n};\nint main() {\n    Test a;\n    Test b = a;\n}"}', '{"correct": false}', NULL, '["面向对象", "构造函数", "拷贝构造", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-J02', 'judgment', '{"stem": "面向对象编程中，封装是指将数据和操作数据的方法绑定在一起，并对外隐藏实现细节。"}', '{"correct": true}', NULL, '["面向对象", "封装", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-J03', 'judgment', '{"stem": "以下代码能够正确统计二叉树中叶子结点的数量。\nint countLeaf(TreeNode* root) {\n    if (!root) return 0;\n    if (!root->left && !root->right) return 1;\n    return countLeaf(root->left) + countLeaf(root->right);\n}"}', '{"correct": true}', NULL, '["二叉树", "递归", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-J04', 'judgment', '{"stem": "广度优先遍历二叉树可用栈来实现。"}', '{"correct": false}', NULL, '["广度优先遍历", "BFS", "队列", "GESP-6"]', 4, 1775530000000);
