INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-J06', 'judgment', '{"stem": "在二叉排序树（BST）中，若某结点的左子树为空，则该结点一定是整棵树中的最小值结点。"}', '{"correct": false}', NULL, '["二叉排序树", "BST", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-J07', 'judgment', '{"stem": "下面的函数能正确判断一棵树是不是二叉排序树（左边的数字要比当前数字小，右边的数字要比当前数字大）。\nbool isBST(TreeNode* root, int minVal, int maxVal) {\n    if (!root) return true;\n    if (root->val <= minVal || root->val >= maxVal)\n        return false;\n    return isBST(root->left, minVal, root->val) &&\n           isBST(root->right, root->val, maxVal);\n}"}', '{"correct": true}', NULL, '["二叉排序树", "BST", "递归", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-J08', 'judgment', '{"stem": "格雷编码相邻两个编码之间必须有多位不同，以避免数据传输错误。"}', '{"correct": false}', NULL, '["格雷码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-J09', 'judgment', '{"stem": "小杨在玩一个闯关游戏，从第 1 关走到第 4 关。每一关的体力消耗如下（下标表示关卡编号）：cost = [0, 3, 5, 2, 4]，其中 cost[i] 表示到达第 i 关需要消耗的体力，cost[0]=0 表示在开始状态，体力消耗为0。小杨每次可以从当前关卡前进 1 步或 2 步。按照上述规则，从第 1 关到第 4 关所需消耗的最小体力为 7。"}', '{"correct": true}', NULL, '["动态规划", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202512-J10', 'judgment', '{"stem": "假定只有一个根节点的树的深度为1，则一棵有n个节点的完全二叉树的深度为⌊log₂n⌋+1。"}', '{"correct": true}', NULL, '["完全二叉树", "树的深度", "OCR修复", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C01', 'choice', '{"stem": "近年来，线上授课变得普遍，很多有助于改善教学效果的设备也逐渐流行，其中包括比较常用的手写板，那么它属于哪类设备？", "options": [{"label": "A", "text": "输入"}, {"label": "B", "text": "输出"}, {"label": "C", "text": "控制"}, {"label": "D", "text": "记录"}]}', '{"correctIndex": 0}', NULL, '["计算机基础", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C02', 'choice', '{"stem": "如果a和b均为int类型的变量，且b的值不为0，那么下列能正确判断\"a是b的3倍\"的表达式是", "options": [{"label": "A", "text": "(a >> 3 == b)"}, {"label": "B", "text": "(a - b) % 3 == 0"}, {"label": "C", "text": "(a / b == 3)"}, {"label": "D", "text": "(a == 3 * b)"}]}', '{"correctIndex": 3}', NULL, '["运算符", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C03', 'choice', '{"stem": "以下不属于面向对象程序设计语言的是", "options": [{"label": "A", "text": "C++"}, {"label": "B", "text": "Python"}, {"label": "C", "text": "Java"}, {"label": "D", "text": "C"}]}', '{"correctIndex": 3}', NULL, '["面向对象", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C04', 'choice', '{"stem": "下面有关C++类定义的说法，错误的是", "options": [{"label": "A", "text": "C++类实例化时，会执行构造函数。"}, {"label": "B", "text": "C++自定义类可以通过定义构造函数实现自动类型转换。"}, {"label": "C", "text": "C++自定义类可以通过重载>、<等运算符实现大小比较。"}, {"label": "D", "text": "C++自定义类可以包含任意类型的成员。"}]}', '{"correctIndex": 3}', NULL, '["面向对象", "类与对象", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C05', 'choice', '{"stem": "有关下面C++代码的说法，错误的是\nclass MyStr {\npublic:\n    char* data;\n    MyStr(const char* str) {\n        data = new char[strlen(str) + 1];\n        strcpy(data, str);\n    }\n};", "options": [{"label": "A", "text": "代码cout << st << endl;会报错，因为没有为MyStr类重载<<运算符。"}, {"label": "B", "text": "第6行代码的data是MyStr类的成员变量。"}, {"label": "C", "text": "代码MyStr st(\"ABC\");不会报错，将执行构造函数。"}, {"label": "D", "text": "代码cout<< st.data <<endl;可输出ABC。"}]}', '{"correctIndex": 0}', NULL, '["面向对象", "运算符重载", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C06', 'choice', '{"stem": "下列关于命名空间的说法错误的是", "options": [{"label": "A", "text": "命名空间可以嵌套，例如namespace A { namespace B { int i;}}。"}, {"label": "B", "text": "命名空间只可以在全局定义。"}, {"label": "C", "text": "命名空间中可以存放变量和函数。"}, {"label": "D", "text": "如果程序中使用了using命令同时引用了多个命名空间，并且命名空间中存在相同的函数，会出现程序运行错误。"}]}', '{"correctIndex": 3}', NULL, '["命名空间", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C07', 'choice', '{"stem": "有关下面C++代码的说法，正确的是\nclass ManyData {\nprivate:\n    int __data[100];\n    int __size;\npublic:\n    ManyData() { __size = 0; }\n    void push(int x) { __data[__size++] = x; }\n    int pop() { return __data[--__size]; }\n};", "options": [{"label": "A", "text": "这段代码不能正常运行。"}, {"label": "B", "text": "ManyData类可用于构造队列（Queue）数据结构。"}, {"label": "C", "text": "在上面代码环境，代码cout<< myData.__data[0] << endl;可以增加到代码main函数末尾（return 0;之前），且不会导致报错。"}, {"label": "D", "text": "可以为ManyData类的push()、pop()函数增加异常处理代码，否则在使用ManyData类时可能导致运行时错误或逻辑错误（不一定局限于上述代码中的main函数）。"}]}', '{"correctIndex": 3}', NULL, '["面向对象", "栈与队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C08', 'choice', '{"stem": "有关下面C++代码的说法，错误的是\nclass MoreData {\nprivate:\n    int __data[100];\n    int __size;\npublic:\n    MoreData() { __size = 0; }\n    MoreData& push(int x) { __data[__size++] = x; return *this; }\n    int pop() { return __data[--__size]; }\n};\nint main() {\n    MoreData myData;\n    myData.push(1).push(2).push(3);\n    return 0;\n}", "options": [{"label": "A", "text": "MoreData类可用于构造队列（Queue）数据结构。"}, {"label": "B", "text": "代码第29行，连续push()的用法将导致编译错误。"}, {"label": "C", "text": "__data是MoreData类的私有成员，只能在类内访问。"}, {"label": "D", "text": "以上说法均没有错误。"}]}', '{"correctIndex": 1}', NULL, '["面向对象", "栈与队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C09', 'choice', '{"stem": "某内容仅会出现ABCDEFG，其对应的出现概率为0.40、0.30、0.15、0.05、0.04、0.03、0.03。按照哈夫曼编码规则，假设B的编码为11，则D的编码为", "options": [{"label": "A", "text": "10010"}, {"label": "B", "text": "10011"}, {"label": "C", "text": "10111"}, {"label": "D", "text": "10001"}]}', '{"correctIndex": 1}', NULL, '["哈夫曼编码", "GESP-6"]', 4, 1775530000000);
