INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202309-C13', 'choice', '{"stem": "青蛙每次能跳1或2步。下面是青蛙跳到第N步台阶C++实现代码。该段代码采用的算法是\nint dp[1000];\nint main() {\n    int N;\n    cin >> N;\n    dp[1] = 1; dp[2] = 2;\n    for (int i = 3; i <= N; i++)\n        dp[i] = dp[i-1] + dp[i-2];\n    cout << dp[N];\n    return 0;\n}", "options": [{"label": "A", "text": "递推算法"}, {"label": "B", "text": "贪心算法"}, {"label": "C", "text": "动态规划算法"}, {"label": "D", "text": "分治算法"}]}', '{"correctIndex": 2}', NULL, '["动态规划", "GESP-6"]', 4, 1775530000000);
