INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C01', 'choice', '{"stem": "面向对象的编程思想主要包括（  ）原则。", "options": [{"label": "A", "text": "贪心、动态规划、回溯"}, {"label": "B", "text": "并发、并行、异步"}, {"label": "C", "text": "递归、循环、分治"}, {"label": "D", "text": "封装、继承、多态"}]}', '{"correctIndex": 3}', NULL, '["面向对象", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C02', 'choice', '{"stem": "运行下列代码，屏幕上输出（  ）。\n#include <iostream>\nusing namespace std;\nclass my_class {\npublic:\n    static int count;\n    my_class() {\n        count++;\n    }\n    ~my_class() {\n        count--;\n    }\n    static void print_count() {\n       cout  << count << \" \";\n    }\n};\nint my_class::count = 0;\nint main() {\n    my_class obj1;\n    my_class::print_count();\n    my_class obj2;\n    obj2.print_count();\n    my_class obj3;\n    obj3.print_count();\n    return 0;\n}", "options": [{"label": "A", "text": "1 1 1"}, {"label": "B", "text": "1 2 3"}, {"label": "C", "text": "1 1 2"}, {"label": "D", "text": "1 2 2"}]}', '{"correctIndex": 1}', NULL, '["面向对象", "静态成员", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C03', 'choice', '{"stem": "运行下列代码，屏幕上输出（  ）。\n#include <iostream>\nusing namespace std;\nclass shape {\nprotected:\n    int width, height;\npublic:\n    shape(int a = 0, int b = 0) {\n        width = a;\n        height = b;\n    }\n    virtual int area() {\n        cout << \"parent class area:\" <<endl;\n        return 0;\n    }\n};\nclass rectangle: public shape {\npublic:\n    rectangle(int a = 0, int b = 0) : shape(a, b) { }\n    int area () {\n        cout << \"rectangle area: \";\n        return (width * height);\n    }\n};\nclass triangle: public shape {\npublic:\n    triangle(int a = 0, int b = 0) : shape(a, b) { }\n    int area () {\n        cout << \"triangle area: \";\n        return (width * height / 2);\n    }\n};\nint main() {\n   shape *pshape;\n   rectangle rec(10, 7);\n   triangle  tri(10, 5);\n   pshape = &rec;\n   pshape->area();\n   pshape = &tri;\n   pshape->area();\n   return 0;\n}", "options": [{"label": "A", "text": "rectangle area: triangle area:"}, {"label": "B", "text": "parent class area: parent class area:"}, {"label": "C", "text": "运行时报错"}, {"label": "D", "text": "编译时报错"}]}', '{"correctIndex": 0}', NULL, '["继承与多态", "虚函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C04', 'choice', '{"stem": "向一个栈顶为hs的链式栈中插入一个指针为s的结点时，应执行（  ）。", "options": [{"label": "A", "text": "hs->next = s;"}, {"label": "B", "text": "s->next = hs; hs = s;"}, {"label": "C", "text": "s->next = hs->next; hs->next = s;"}, {"label": "D", "text": "s->next = hs; hs = hs->next;"}]}', '{"correctIndex": 1}', NULL, '["栈与队列", "链表", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C05', 'choice', '{"stem": "在栈数据结构中，元素的添加和删除是按照什么原则进行的？", "options": [{"label": "A", "text": "先进先出"}, {"label": "B", "text": "先进后出"}, {"label": "C", "text": "最小值先出"}, {"label": "D", "text": "随机顺序"}]}', '{"correctIndex": 1}', NULL, '["栈与队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C06', 'choice', '{"stem": "要实现将一个输入的十进制正整数转化为二进制表示，下面横线上应填入的代码为（  ）。\n#include <iostream>\nusing namespace std;\nstack<int> ten2bin(int n) {\n    stack<int> st;\n    int r, m;\n    r = n % 2;\n    m = n / 2;\n    st.push(r);\n    while (m != 1) {\n        r = m % 2;\n        st.push(r);\n        m = m / 2;\n    }\n    st.push(m);\n    return st;\n}\nint main() {\n    int n;\n    cin >> n;\n    stack<int> bin;\n    bin = ten2bin(n);\n    while (!bin.empty()) {\n        _____________________ // 在此处填入代码\n    }\n    return 0;\n}", "options": [{"label": "A", "text": "cout << bin.top();  bin.pop();"}, {"label": "B", "text": "bin.pop(); cout << bin.top();"}, {"label": "C", "text": "cout << bin.back();  bin.pop();"}, {"label": "D", "text": "cout << bin.front();  bin.pop();"}]}', '{"correctIndex": 0}', NULL, '["栈与队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C07', 'choice', '{"stem": "下面定义了一个循环队列的类，请补全判断队列是否满的函数，横向上应填写（  ）。\n#include <iostream>\nusing namespace std;\nclass circular_queue {\nprivate:\n    int *arr; // 数组用于存储队列元素\n    int capacity; // 队列容量\n    int front; // 队头指针\n    int rear; // 队尾指针\npublic:\n    circular_queue(int size) {\n        capacity = size + 1; // 为了避免队列满时与队列空时指针相等的情况，多预留一个空间\n        arr = new int[capacity];\n        front = 0;\n        rear = 0;\n    }\n    ~circular_queue() {\n        delete[] arr;\n    }\n    bool is_empty() {\n        return front == rear;\n    }\n    bool is_full() {\n        ________________ // 在此处填入代码\n    }\n    void en_queue(int data) {\n        if (is_full()) {\n            cout << \"队列已满，无法入队！\" << endl;\n            return -1;\n        }\n        arr[rear] = data;\n        rear = (rear + 1) % capacity;\n        return 1;\n    }\n    int de_queue() {\n        if (is_empty()) {\n            cout << \"队列为空，无法出队！\" << endl;\n            return -1; // 出队失败，返回一个特殊值\n        }\n        int data = arr[front];\n        front = (front + 1) % capacity;\n        return data;\n    }\n};", "options": [{"label": "A", "text": "return (rear + 1) % capacity == front;"}, {"label": "B", "text": "return rear % capacity == front;"}, {"label": "C", "text": "return rear == front;"}, {"label": "D", "text": "return (rear + 1) == front;"}]}', '{"correctIndex": 0}', NULL, '["栈与队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C08', 'choice', '{"stem": "对\"classmycls\"使用哈夫曼（Huffman）编码，最少需要（  ）比特。", "options": [{"label": "A", "text": "10"}, {"label": "B", "text": "20"}, {"label": "C", "text": "25"}, {"label": "D", "text": "30"}]}', '{"correctIndex": 2}', NULL, '["哈夫曼编码", "GESP-6"]', 4, 1775530000000);
