INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C11', 'choice', '{"stem": "在求解最优化问题时，动态规划常常涉及到两个重要性质，即最优子结构和(  )。", "options": [{"label": "A", "text": "重叠子问题"}, {"label": "B", "text": "分治法"}, {"label": "C", "text": "贪心策略"}, {"label": "D", "text": "回溯算法"}]}', '{"correctIndex": 0}', NULL, '["动态规划", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C12', 'choice', '{"stem": "青蛙每次能跳1或2步，下面代码计算青蛙跳到第n步台阶有多少种不同跳法。则下列说法，错误的是(  )。\nint jump_recur(int n) {\n    if (n == 1) return 1;\n    if (n == 2) return 2;\n    return jump_recur(n - 1) + jump_recur(n - 2);\n}\nint jump_dp(int n) {\n    vector<int> dp(n + 1); // 创建一个动态规划数组，用于保存已计算的值\n    // 初始化前两个数\n    dp[1] = 1;\n    dp[2] = 2;\n    // 从第三个数开始计算斐波那契数列\n    for (int i = 3; i <= n; ++i) {\n        dp[i] = dp[i - 1] + dp[i - 2];\n    }\n    return dp[n];\n}", "options": [{"label": "A", "text": "函数jump_recur()采用递归方式。"}, {"label": "B", "text": "函数jump_dp()采用动态规划方法。"}, {"label": "C", "text": "当n较大时，函数jump_recur()存在大量重复计算，执行效率低。"}, {"label": "D", "text": "函数jump_recur()代码量小，执行效率高。"}]}', '{"correctIndex": 3}', NULL, '["动态规划", "时间复杂度", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C13', 'choice', '{"stem": "阅读以下二叉树的广度优先搜索代码:\n#include <iostream>\n#include <queue>\nusing namespace std;\n// 二叉树节点的定义\nstruct TreeNode {\n    int val;\n    TreeNode* left;\n    TreeNode* right;\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n};\n// 宽度优先搜索（BFS）迭代实现\nTreeNode* bfs(TreeNode* root, int a) {\n    if (root == nullptr) return nullptr;\n    queue<TreeNode*> q;\n    q.push(root);\n    while (!q.empty()) {\n        TreeNode* node = q.front();\n        q.pop();\n        if (node->val == a)\n            return node;\n        cout << node->val << \" \"; // 先访问当前节点\n        if (node->left) q.push(node->left); // 将左子节点入队\n        if (node->right) q.push(node->right); // 将右子节点入队\n    }\n    return nullptr;\n}\n使用以上算法，在给定的树搜索数值时，可能的输出是(  )。", "options": [{"label": "A", "text": "5 2 -4 3 17 9"}, {"label": "B", "text": "-4 2 3 5 9 17"}, {"label": "C", "text": "5 2 17 -4 3 9"}, {"label": "D", "text": "以上都不对"}]}', '{"correctIndex": 2}', NULL, '["二叉树", "搜索算法", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202406-C14', 'choice', '{"stem": "同上题中的二叉树，阅读以下二叉树的深度优先搜索代码:\n#include <iostream>\n#include <stack>\nusing namespace std;\n// 非递归深度优先搜索（DFS）\nTreeNode* dfs(TreeNode* root, int a) {\n    if (root == nullptr) return nullptr;\n    stack<TreeNode*> stk;\n    stk.push(root);\n    while (!stk.empty()) {\n        TreeNode* node = stk.top();\n        stk.pop();\n        if (node->val == a)\n            return node;\n        cout << node->val << \" \"; // 访问当前节点\n        if (node->right) stk.push(node->right); // 先压入右子节点\n        if (node->left) stk.push(node->left); // 再压入左子节点\n    }\n    return nullptr;\n}\n使用以上算法，在二叉树搜索数值时，可能的输出是(  )。", "options": [{"label": "A", "text": "5 2 -4 3 17 9"}, {"label": "B", "text": "-4 2 3 5 9 17"}, {"label": "C", "text": "5 2 17 -4 3 9"}, {"label": "D", "text": "以上都不对"}]}', '{"correctIndex": 0}', NULL, '["二叉树", "搜索算法", "GESP-6"]', 4, 1775530000000);
