INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C01', 'choice', '{"stem": "在面向对象编程中，类是一种重要的概念。下面关于类的描述中，不正确的是（ ）。", "options": [{"label": "A", "text": "类是一个抽象的概念，用于描述具有相同属性和行为的对象集合。"}, {"label": "B", "text": "类可以包含属性和方法，属性用于描述对象的状态，方法用于描述对象的行为。"}, {"label": "C", "text": "类可以被实例化，生成具体的对象。"}, {"label": "D", "text": "类一旦定义后，其属性和方法不能被修改或扩展。"}]}', '{"correctIndex": 3}', NULL, '["面向对象", "类", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C02', 'choice', '{"stem": "哈夫曼编码是一种数据压缩算法。以下关于哈夫曼编码的描述中，不正确的是（ ）。", "options": [{"label": "A", "text": "哈夫曼编码是一种变长编码，频率高的字符使用较短的编码，频率低的字符使用较长的编码。"}, {"label": "B", "text": "在构造哈夫曼树时，频率越低的字符离根节点越近，频率越高的字符离根节点越远。"}, {"label": "C", "text": "哈夫曼编码的生成过程基于贪心算法，每次选择频率最低的两个节点进行合并。"}, {"label": "D", "text": "哈夫曼编码是一种前缀编码，任何一个字符的编码都不会是另一个字符编码的前缀，因此可以实现唯一解码。"}]}', '{"correctIndex": 1}', NULL, '["哈夫曼编码", "贪心算法", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C03', 'choice', '{"stem": "以下代码实现了树的哪种遍历方式？\nvoid traverse(TreeNode* root) {\n  if (root == nullptr) return;\n  cout << root->val << \" \";\n  traverse(root->left);\n  traverse(root->right);\n}", "options": [{"label": "A", "text": "前序遍历"}, {"label": "B", "text": "中序遍历"}, {"label": "C", "text": "后序遍历"}, {"label": "D", "text": "层次遍历"}]}', '{"correctIndex": 0}', NULL, '["树", "遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C04', 'choice', '{"stem": "以下关于完全二叉树的代码描述，正确的是（ ）。\nbool isCompleteTree(TreeNode* root) {\n  if (root == nullptr) return true;\n  queue<TreeNode*> q;\n  q.push(root);\n  bool hasNull = false;\n  while (!q.empty()) {\n    TreeNode* node = q.front(); q.pop();\n    if (node == nullptr) { hasNull = true; }\n    else {\n      if (hasNull) return false;\n      q.push(node->left);\n      q.push(node->right);\n    }\n  }\n  return true;\n}", "options": [{"label": "A", "text": "该代码用于判断一棵树是否为满二叉树"}, {"label": "B", "text": "该代码用于判断一棵树是否为完全二叉树"}, {"label": "C", "text": "该代码用于判断一棵树是否为二叉搜索树"}, {"label": "D", "text": "该代码用于计算树的高度"}]}', '{"correctIndex": 1}', NULL, '["完全二叉树", "队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C05', 'choice', '{"stem": "以下代码实现了二叉排序树的哪种操作？\nTreeNode* op(TreeNode* root, int val) {\n  if (root == nullptr) return new TreeNode(val);\n  if (val < root->val) root->left = op(root->left, val);\n  else root->right = op(root->right, val);\n  return root;\n}", "options": [{"label": "A", "text": "查找"}, {"label": "B", "text": "插入"}, {"label": "C", "text": "删除"}, {"label": "D", "text": "遍历"}]}', '{"correctIndex": 1}', NULL, '["二叉排序树", "插入", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C06', 'choice', '{"stem": "给定字符集 {A, B, C, D} 的出现频率分别为 {5, 1, 6, 2}，则正确的哈夫曼编码是（ ）。", "options": [{"label": "A", "text": "A:0, B:100, C:11, D:101"}, {"label": "B", "text": "A:11, B:100, C:0, D:101"}, {"label": "C", "text": "A:0, B:101, C:11, D:100"}, {"label": "D", "text": "A:10, B:101, C:0, D:100"}]}', '{"correctIndex": 1}', NULL, '["哈夫曼编码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C07', 'choice', '{"stem": "关于动态规划的描述，正确的是（ ）。", "options": [{"label": "A", "text": "动态规划算法的时间复杂度总是低于贪心算法。"}, {"label": "B", "text": "动态规划要求问题必须具有最优子结构和重叠子问题两个性质。"}, {"label": "C", "text": "动态规划通过递归实现时不需要存储中间结果。"}, {"label": "D", "text": "动态规划的核心思想是将问题分解为互不重叠的子问题。"}]}', '{"correctIndex": 1}', NULL, '["动态规划", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C08', 'choice', '{"stem": "以下代码中，类的构造函数被调用了（ ）次。\nclass MyClass { public: MyClass() { cout << \"Constructor called!\" << endl; } };\nint main() { MyClass obj1; MyClass obj2 = obj1; return 0; }", "options": [{"label": "A", "text": "1"}, {"label": "B", "text": "2"}, {"label": "C", "text": "3"}, {"label": "D", "text": "0"}]}', '{"correctIndex": 0}', NULL, '["类", "构造函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C09', 'choice', '{"stem": "以下代码实现了循环队列的哪种操作？\nbool enQueue(int value) {\n  if (isFull()) return false;\n  if (isEmpty()) front = 0;\n  rear = (rear + 1) % size;\n  arr[rear] = value;\n  return true;\n}", "options": [{"label": "A", "text": "入队"}, {"label": "B", "text": "出队"}, {"label": "C", "text": "查看队首元素"}, {"label": "D", "text": "判断队列是否为空"}]}', '{"correctIndex": 0}', NULL, '["循环队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C10', 'choice', '{"stem": "以下代码实现了二叉树的深度优先搜索（DFS），并统计叶子结点的数量，则横线上应填写（ ）。\nint countLeafNodes(TreeNode* root) {\n  if (root == nullptr) return 0;\n  stack<TreeNode*> s; s.push(root);\n  int count = 0;\n  while (!s.empty()) {\n    TreeNode* node = s.top(); s.pop();\n    if (!node->left && !node->right) count++;\n    if (node->right) s.push(node->right);\n    ________\n  }\n  return count;\n}", "options": [{"label": "A", "text": "if (node->left) s.push(node->left);"}, {"label": "B", "text": "if (node->left) s.pop(node->left);"}, {"label": "C", "text": "if (node->left) s.front(node->left);"}, {"label": "D", "text": "if (node->left) s.push(node->right);"}]}', '{"correctIndex": 0}', NULL, '["二叉树", "DFS", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C11', 'choice', '{"stem": "以下代码实现了二叉树的广度优先搜索（BFS），并查找特定值的节点，则横线上应填写（ ）。\nTreeNode* findNode(TreeNode* root, int target) {\n  if (root == nullptr) return nullptr;\n  queue<TreeNode*> q; q.push(root);\n  while (!q.empty()) {\n    TreeNode* current = q.front(); q.pop();\n    if (current->val == target) return current;\n    ________\n  }\n  return nullptr;\n}", "options": [{"label": "A", "text": "if (current->left) q.push(current->left); if (current->right) q.push(current->right);"}, {"label": "B", "text": "if (current->left) q.pop(current->left); if (current->right) q.pop(current->right);"}, {"label": "C", "text": "if (current->left) q.front(current->left); if (current->right) q.front(current->right);"}, {"label": "D", "text": "if (current->left) q.push(current->right); if (current->right) q.push(current->left);"}]}', '{"correctIndex": 0}', NULL, '["二叉树", "BFS", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C12', 'choice', '{"stem": "以下代码用于生成 n 位格雷编码。横线上应填写（ ）。\nvector<string> generateGrayCode(int n) {\n  if (n == 0) return {\"0\"};\n  if (n == 1) return {\"0\", \"1\"};\n  vector<string> prev = generateGrayCode(n - 1);\n  vector<string> result;\n  for (string s : prev) result.push_back(\"0\" + s);\n  for (int i = prev.size() - 1; i >= 0; i--) ________\n  return result;\n}", "options": [{"label": "A", "text": "result.push_back(\"1\" + prev[i]);"}, {"label": "B", "text": "result.push_back(\"0\" + prev[i]);"}, {"label": "C", "text": "result.push_back(prev[i] + \"1\");"}, {"label": "D", "text": "result.push_back(prev[i] + \"0\");"}]}', '{"correctIndex": 0}', NULL, '["格雷编码", "递归", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C13', 'choice', '{"stem": "以下代码实现了 0/1 背包问题的动态规划解法，横线上应填写（ ）。\nint knapsack(int W, vector<int>& weights, vector<int>& values) {\n  int n = weights.size();\n  vector<vector<int>> dp(n + 1, vector<int>(W + 1, 0));\n  for (int i = 1; i <= n; i++) {\n    for (int j = 1; j <= W; j++) {\n      if (weights[i-1] > j) dp[i][j] = dp[i-1][j];\n      else dp[i][j] = max(________);\n    }\n  }\n  return dp[n][W];\n}", "options": [{"label": "A", "text": "dp[i-1][j], values[i-1]"}, {"label": "B", "text": "dp[i-1][j], dp[i-1][j - weights[i-1]] + values[i-1]"}, {"label": "C", "text": "dp[i][j-1], values[i-1]"}, {"label": "D", "text": "dp[i-1][j - weights[i-1]] + values[i-1], dp[i][j-1]"}]}', '{"correctIndex": 1}', NULL, '["动态规划", "背包问题", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C14', 'choice', '{"stem": "以下代码用于检查字符串中的括号是否匹配，横线上应填写（ ）。\nbool isBalanced(string s) {\n  stack<char> st;\n  for (char c : s) {\n    if (c == ''('' || c == ''['' || c == ''{'') st.push(c);\n    else {\n      if (st.empty()) return false;\n      char top = st.top(); st.pop();\n      if ((c=='')'' && top!=''('') || (c=='']'' && top!=''['') || (c==''}'' && top!=''{'')) return false;\n    }\n  }\n  return ________;\n}", "options": [{"label": "A", "text": "true"}, {"label": "B", "text": "false"}, {"label": "C", "text": "st.empty()"}, {"label": "D", "text": "!st.empty()"}]}', '{"correctIndex": 2}', NULL, '["栈", "括号匹配", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202503-C15', 'choice', '{"stem": "关于下面代码，说法错误的是（ ）。\nclass Shape { public: Shape(const string& n) : name(n) {} virtual double area() const { return 0.0; } };\nclass Circle : public Shape { ... };\nclass Rectangle : public Shape { ... };\nint main() { Circle circle(\"MyCircle\", 5.0); Rectangle rectangle(\"MyRectangle\", 4.0, 6.0); Shape* shapePtr = &circle; shapePtr = &rectangle; }", "options": [{"label": "A", "text": "语句 Shape* shapePtr = &circle; 和 shapePtr = &rectangle; 出现编译错误"}, {"label": "B", "text": "Shape 为基类，Circle 和 Rectangle 是派生类"}, {"label": "C", "text": "通过继承，Circle 和 Rectangle 复用了 Shape 的属性和方法，并扩展了新的功能"}, {"label": "D", "text": "Circle 和 Rectangle 通过重写基类的虚函数 area 和基类指针，实现了运行时多态"}]}', '{"correctIndex": 0}', NULL, '["面向对象", "多态", "继承", "GESP-6"]', 4, 1775530000000);
