INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C02', 'choice', '{"stem": "为了让 Dog 类的构造函数能正确地调用其父类 Animal 的构造方法，横线处应填入（ ）。\nclass Animal { public: std::string name; Animal(std::string str) : name(str) { std::cout << \"Animal created\\n\"; } virtual void speak() { cout << \"Animal speaks\" << endl; } };\nclass Dog : public Animal { std::string breed; public: Dog(std::string name, std::string b) : ________, breed(b) { std::cout << \"Dog created\\n\"; } void speak() override { cout << \"Dog barks\" << endl; } };", "options": [{"label": "A", "text": "Animal(name)"}, {"label": "B", "text": "super(name)"}, {"label": "C", "text": "Animal::Animal(name)"}, {"label": "D", "text": "Animal()"}]}', '{"correctIndex": 0}', NULL, '["继承", "构造函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C03', 'choice', '{"stem": "代码同上一题，代码执行结果是（ ）。\nint main() { Animal* p = new Dog(\"Rex\", \"Labrador\"); p->speak(); delete p; return 0; }", "options": [{"label": "A", "text": "输出 Animal speaks"}, {"label": "B", "text": "输出 Dog barks"}, {"label": "C", "text": "编译错误"}, {"label": "D", "text": "程序崩溃"}]}', '{"correctIndex": 1}', NULL, '["虚函数", "多态", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C04', 'choice', '{"stem": "以下关于栈和队列的代码，执行后输出是（ ）。\nstack<int> s; queue<int> q;\nfor (int i = 1; i <= 3; ++i) { s.push(i); q.push(i); }\ncout << s.top() << \" \" << q.front() << endl;", "options": [{"label": "A", "text": "1 3"}, {"label": "B", "text": "3 1"}, {"label": "C", "text": "3 3"}, {"label": "D", "text": "1 1"}]}', '{"correctIndex": 1}', NULL, '["栈", "队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C05', 'choice', '{"stem": "在一个循环队列中，front 是指向队头的指针，rear 指向队尾的指针，队列最大容量为 maxSize。判断队列已满的条件是（ ）。", "options": [{"label": "A", "text": "rear == front"}, {"label": "B", "text": "(rear + 1) % maxSize == front"}, {"label": "C", "text": "(rear - 1 + maxSize) % maxSize == front"}, {"label": "D", "text": "(rear - 1) == front"}]}', '{"correctIndex": 1}', NULL, '["循环队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C06', 'choice', '{"stem": "（ ）只有最底层的节点未被填满，且最底层节点尽量靠左填充。", "options": [{"label": "A", "text": "完美二叉树"}, {"label": "B", "text": "完全二叉树"}, {"label": "C", "text": "完满二叉树"}, {"label": "D", "text": "平衡二叉树"}]}', '{"correctIndex": 1}', NULL, '["完全二叉树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C07', 'choice', '{"stem": "在使用数组表示完全二叉树时，如果一个节点的索引为 i（从 1 开始计数），那么其左子节点的索引通常是（ ）。", "options": [{"label": "A", "text": "i+1"}, {"label": "B", "text": "2i"}, {"label": "C", "text": "2i+1"}, {"label": "D", "text": "i/2"}]}', '{"correctIndex": 1}', NULL, '["二叉树", "数组存储", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C08', 'choice', '{"stem": "已知一棵二叉树的前序遍历序列为 GDAFEMHZ，中序遍历序列为 ADFGEHMZ，则其后序遍历序列为（ ）。", "options": [{"label": "A", "text": "ADFGEHMZ"}, {"label": "B", "text": "ADFGHMEZ"}, {"label": "C", "text": "AFDGEMZH"}, {"label": "D", "text": "AFDHZMEG"}]}', '{"correctIndex": 3}', NULL, '["二叉树遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C09', 'choice', '{"stem": "设有字符集 {a, b, c, d, e}，其出现频率分别为 {5, 8, 12, 15, 20}，得到的哈夫曼编码为（ ）。", "options": [{"label": "A", "text": "a: 010, b: 011, c: 00, d: 10, e: 11"}, {"label": "B", "text": "a: 00, b: 10, c: 011, d: 100, e: 111"}, {"label": "C", "text": "a: 10, b: 01, c: 011, d: 100, e: 111"}, {"label": "D", "text": "a: 100, b: 01, c: 011, d: 100, e: 00"}]}', '{"correctIndex": 0}', NULL, '["哈夫曼编码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C10', 'choice', '{"stem": "3 位格雷编码中，编码 101 之后的下一个编码不可能是（ ）。", "options": [{"label": "A", "text": "100"}, {"label": "B", "text": "111"}, {"label": "C", "text": "110"}, {"label": "D", "text": "001"}]}', '{"correctIndex": 2}', NULL, '["格雷码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C11', 'choice', '{"stem": "请将下列 C++ 实现的深度优先搜索（DFS）代码补充完整，横线处应填入（ ）。\nvoid dfs(TreeNode* root, vector<int>& result) {\n  if (root == nullptr) return;\n  ________\n}", "options": [{"label": "A", "text": "result.push_back(root->val); dfs(root->left, result); dfs(root->right, result);"}, {"label": "B", "text": "dfs(root->left, result); dfs(root->right, result); result.push_back(root->val);"}, {"label": "C", "text": "dfs(root->left, result); result.push_back(root->val); dfs(root->right, result);"}, {"label": "D", "text": "result.push_back(root->val); dfs(root->right, result); dfs(root->left, result);"}]}', '{"correctIndex": 0}', NULL, '["DFS", "树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C12', 'choice', '{"stem": "给定一个二叉树，返回每一层中最大的节点值，结果以数组形式返回，横线处应填入（ ）。", "options": [{"label": "A", "text": "node = q.back(); q.pop();"}, {"label": "B", "text": "node = q.top(); q.pop();"}, {"label": "C", "text": "node = q.front(); q.pop_front();"}, {"label": "D", "text": "node = q.front(); q.pop();"}]}', '{"correctIndex": 3}', NULL, '["BFS", "树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C13', 'choice', '{"stem": "下面代码实现一个二叉排序树的插入函数（没有相同的数值），横线处应填入（ ）。\nvoid insert(TreeNode*& root, int key) {\n  if (!root) { root = new TreeNode(key); return; }\n  ________\n}", "options": [{"label": "A", "text": "if (key < root->val) insert(root->left, key); else if (key > root->val) insert(root->right, key);"}, {"label": "B", "text": "if (key > root->val) insert(root->left, key); else insert(root->right, key);"}, {"label": "C", "text": "insert(root->left, key); insert(root->right, key);"}, {"label": "D", "text": "if (key < root->val) insert(root->right, key); else insert(root->left, key);"}]}', '{"correctIndex": 0}', NULL, '["二叉排序树", "插入", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C14', 'choice', '{"stem": "以下关于动态规划算法特性的描述，正确的是（ ）。", "options": [{"label": "A", "text": "子问题相互独立，不重叠"}, {"label": "B", "text": "问题包含重叠子问题和最优子结构"}, {"label": "C", "text": "只能从底至顶迭代求解"}, {"label": "D", "text": "必须使用递归实现，不能使用迭代"}]}', '{"correctIndex": 1}', NULL, '["动态规划", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-C15', 'choice', '{"stem": "给定 n 个物品和一个最大承重为 W 的背包，每个物品有一个重量 wi 和价值 vi，每个物品只能选择放或不放。目标是选择若干个物品放入背包，使得总价值最大，且总重量不超过 W。关于下面代码，说法正确的是（ ）。\nint knapsack1D(int W, vector<int>& wt, vector<int>& val, int n) {\n  vector<int> dp(W+1, 0);\n  for (int i = 0; i < n; ++i) {\n    for (int w = W; w >= wt[i]; --w) { dp[w] = max(dp[w], dp[w - wt[i]] + val[i]); }\n  }\n  return dp[W];\n}", "options": [{"label": "A", "text": "该算法不能处理背包容量为 0 的情况"}, {"label": "B", "text": "外层循环 i 遍历背包容量，内层遍历物品"}, {"label": "C", "text": "从大到小遍历 w 是为了避免重复使用同一物品"}, {"label": "D", "text": "这段代码计算的是最小重量而非最大价值"}]}', '{"correctIndex": 2}', NULL, '["动态规划", "背包问题", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J01', 'judgment', '{"stem": "构造函数可以被声明为 virtual。"}', '{"correct": false}', NULL, '["虚函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J02', 'judgment', '{"stem": "给定一组字符及其出现的频率，构造出的哈夫曼树是唯一的。"}', '{"correct": false}', NULL, '["哈夫曼树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J03', 'judgment', '{"stem": "为了实现一个队列，使其出队操作（pop）的时间复杂度为 O(1) 并且避免数组删除首元素的 O(n) 问题，一种常见且有效的方法是使用环形数组，通过调整队首和队尾指针来实现。"}', '{"correct": true}', NULL, '["队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J04', 'judgment', '{"stem": "对一棵二叉排序树进行中序遍历，可以得到一个递增的有序序列。"}', '{"correct": true}', NULL, '["二叉排序树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J05', 'judgment', '{"stem": "如果二叉搜索树在连续的插入和删除操作后，所有节点都偏向一侧，导致其退化为类似于链表的结构，这时其查找、插入、删除操作的时间复杂度会从理想情况下的 O(log n) 退化到 O(n)。"}', '{"correct": true}', NULL, '["二叉搜索树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J06', 'judgment', '{"stem": "执行下列代码，my_dog.name 的最终值是 Charlie。\nclass Dog { public: std::string name; Dog(std::string str) : name(str) {} };\nint main() { Dog my_dog(\"Buddy\"); my_dog.name = \"Charlie\"; return 0; }"}', '{"correct": true}', NULL, '["类与对象", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J07', 'judgment', '{"stem": "下列 C++ 代码可以成功编译，并且子类 Child 的实例能通过其成员函数访问父类 Parent 的属性 value。\nclass Parent { private: int value = 100; };\nclass Child : public Parent { public: int get_private_val() { return value; } };"}', '{"correct": false}', NULL, '["继承", "访问控制", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J08', 'judgment', '{"stem": "下列代码中的 tree 向量，表示的是一棵完全二叉树（-1 代表空节点）按照层序遍历的结果。\nvector<int> tree = {1, 2, 3, 4, -1, 6, 7};"}', '{"correct": false}', NULL, '["完全二叉树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J09', 'judgment', '{"stem": "在树的深度优先搜索（DFS）中，使用栈作为辅助数据结构以实现「先进后出」的访问顺序。"}', '{"correct": true}', NULL, '["DFS", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202506-J10', 'judgment', '{"stem": "下面代码采用动态规划求解零钱兑换问题：给定 n 种硬币，第 i 种硬币的面值为 coins[i-1]，目标金额为 amt，每种硬币可以重复选取，求能够凑出目标金额的最少硬币数量；如果不能凑出目标金额，返回 -1。\nint coinChangeDPComp(vector<int> &coins, int amt) {\n  int n = coins.size(); int MAX = amt + 1; vector<int> dp(amt + 1, MAX); dp[0] = 0;\n  for (int i = 1; i <= n; i++) {\n    for (int a = 1; a <= amt; a++) {\n      if (coins[i - 1] > a) dp[a] = dp[a];\n      else dp[a] = min(dp[a], dp[a - coins[i - 1]] + 1);\n    }\n  }\n  return dp[amt] != MAX ? dp[amt] : -1;\n}"}', '{"correct": true}', NULL, '["动态规划", "零钱兑换", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C01', 'choice', '{"stem": "下列关于 C++ 中类的描述，正确的是（）。", "options": [{"label": "A", "text": "如果类没有用户声明的构造函数，那么编译器会隐式声明一个默认构造函数"}, {"label": "B", "text": "类的析构函数可以被重载，一个类可以有多个析构函数"}, {"label": "C", "text": "类中的所有成员都必须声明为 public"}, {"label": "D", "text": "类和结构体在 C++ 中没有区别，包括默认访问权限也相同"}]}', '{"correctIndex": 0}', NULL, '["C++", "类", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C02', 'choice', '{"stem": "下列代码中，s1->draw(); 和 s2->draw(); 输出不同结果的主要原因是（）。", "options": [{"label": "A", "text": "draw() 是普通成员函数"}, {"label": "B", "text": "Shape 中的 draw() 被声明为虚函数"}, {"label": "C", "text": "Circle 和 Rectangle 中使用了 public 继承"}, {"label": "D", "text": "指针变量名不同"}]}', '{"correctIndex": 1}', NULL, '["多态", "虚函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C03', 'choice', '{"stem": "下面的代码在 main() 中有一行会导致编译错误，请找出来。\nclass Pet {\n  public: Pet(string n, int a) : name(n), age(a) {}\n  string getName() { return name; }\n  void birthday() { age++; }\n  private: string name; int age;\n};\nint main() {\n  Pet cat(\"奶茶\", 2);\n  cout << cat.getName(); // ①\n  cat.birthday(); // ②\n  cat.name = \"大橘\"; // ③\n  cout << cat.getName(); // ④\n}", "options": [{"label": "A", "text": "第 ①行"}, {"label": "B", "text": "第 ②行"}, {"label": "C", "text": "第 ③行"}, {"label": "D", "text": "第 ④行"}]}', '{"correctIndex": 2}', NULL, '["C++", "访问控制", "封装", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C04', 'choice', '{"stem": "游乐园的过山车每次限坐 4 人，用循环队列管理排队（容量 MAX=5，空一格判满）。下面代码执行后，循环队列是否已满？rear 的值是多少？\nconst int MAX = 5;\nint queue[MAX]; int front = 0, rear = 0;\nvoid enqueue(int x) { queue[rear] = x; rear = (rear + 1) % MAX; }\nvoid dequeue() { front = (front + 1) % MAX; }\nint main() { enqueue(1); enqueue(2); enqueue(3); enqueue(4); dequeue(); dequeue(); enqueue(5); enqueue(6); }", "options": [{"label": "A", "text": "已满，rear = 1"}, {"label": "B", "text": "未满，rear = 1"}, {"label": "C", "text": "已满，rear = 2"}, {"label": "D", "text": "未满，rear = 4"}]}', '{"correctIndex": 0}', NULL, '["循环队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C05', 'choice', '{"stem": "在以下计算机应用场景中，最适合使用循环队列的是（）。", "options": [{"label": "A", "text": "函数调用过程中，保存局部变量和返回地址"}, {"label": "B", "text": "表达式求值中的运算符优先级处理"}, {"label": "C", "text": "操作系统中的进程优先级调度（高优先级先执行）"}, {"label": "D", "text": "生产者和消费者问题中的共享缓冲区"}]}', '{"correctIndex": 3}', NULL, '["循环队列", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C06', 'choice', '{"stem": "在二叉搜索树（BST）中，若中序遍历的序列为 {1, 2, 3, 4, 5}，且先序遍历的第一个元素为 3，下列说法正确的是（）。", "options": [{"label": "A", "text": "该树一定是一棵完全二叉树"}, {"label": "B", "text": "元素 4 和 5 不可能是兄弟节点"}, {"label": "C", "text": "元素 1 所在节点的深度可能大于 3（根节点深度为 1）"}, {"label": "D", "text": "元素 2 一定是元素 1 的父节点"}]}', '{"correctIndex": 1}', NULL, '["二叉搜索树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C07', 'choice', '{"stem": "某二叉树共有 10 个结点，记为 A~J，已知它的先序遍历序列为：A B D H I E C F J G，中序遍历序列为：H D I B E A F J C G，则该二叉树的后序遍历序列是（）。", "options": [{"label": "A", "text": "H I D E B J F G C A"}, {"label": "B", "text": "H I D B E J F G C A"}, {"label": "C", "text": "I H D E B J F G C A"}, {"label": "D", "text": "H I D E B F J G C A"}]}', '{"correctIndex": 0}', NULL, '["二叉树遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C08', 'choice', '{"stem": "下列关于树的遍历的说法中，正确的一项是（）。", "options": [{"label": "A", "text": "对任意一棵树进行深度优先遍历，所得序列一定唯一"}, {"label": "B", "text": "已知一棵二叉树的先序遍历和后序遍历序列，可以唯一确定这棵二叉树"}, {"label": "C", "text": "已知一棵二叉树的先序遍历和中序遍历序列，可以唯一确定这棵二叉树"}, {"label": "D", "text": "已知一棵二叉树的先序遍历序列，可以唯一确定这棵二叉树"}]}', '{"correctIndex": 2}', NULL, '["二叉树遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C09', 'choice', '{"stem": "有 6 个字符，它们出现的次数分别为：{2, 3, 3, 4, 6, 8}，现在用哈夫曼编码为这些字符编码，最小加权路径长度 WPL 的值为（）。", "options": [{"label": "A", "text": "58"}, {"label": "B", "text": "60"}, {"label": "C", "text": "62"}, {"label": "D", "text": "64"}]}', '{"correctIndex": 3}', NULL, '["哈夫曼编码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C10', 'choice', '{"stem": "对 n 个不同符号进行哈夫曼编码。若生成的哈夫曼树共有 m 个结点，则 n 的值是（）。", "options": [{"label": "A", "text": "(m+1)/2"}, {"label": "B", "text": "(m-1)/2"}, {"label": "C", "text": "m-1"}, {"label": "D", "text": "m"}]}', '{"correctIndex": 0}', NULL, '["哈夫曼树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C11', 'choice', '{"stem": "关于格雷编码（Gray Code），下列说法正确的是（）。", "options": [{"label": "A", "text": "格雷编码中，编码位数越多，相邻编码之间变化的位数也越多"}, {"label": "B", "text": "格雷编码中，相邻两个编码的二进制位恰好有一位不同"}, {"label": "C", "text": "格雷编码就是把普通二进制编码按位取反后得到的结果"}, {"label": "D", "text": "格雷编码不能用于数字电路和状态转换的设计中"}]}', '{"correctIndex": 1}', NULL, '["格雷码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C12', 'choice', '{"stem": "给定一棵二叉树，采用广度优先搜索(BFS)算法，返回右视图所有节点的值。补全代码横线。\nvector<int> rightSideView(TreeNode* root) {\n  unordered_map<int, int> rightmostValueAtDepth;\n  int max_depth = -1;\n  queue<TreeNode*> nodeQueue; queue<int> depthQueue;\n  // ... push logic ...\n  while (!nodeQueue.empty()) { ... }\n  vector<int> rightView;\n  for (int depth = 0; ________; ++depth) {\n    rightView.push_back(rightmostValueAtDepth[depth]);\n  }\n}", "options": [{"label": "A", "text": "depth < max_depth"}, {"label": "B", "text": "depth <= max_depth"}, {"label": "C", "text": "depth + 1 < max_depth"}, {"label": "D", "text": "depth < nodeQueue.size()"}]}', '{"correctIndex": 1}', NULL, '["BFS", "二叉树", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C13', 'choice', '{"stem": "下列关于树的深度优先搜索（DFS）的说法中，正确的是（）。", "options": [{"label": "A", "text": "对树进行 DFS 时，一定按层从上到下依次访问结点"}, {"label": "B", "text": "对任意一棵树进行 DFS，得到的遍历序列唯一"}, {"label": "C", "text": "对一棵树进行 DFS 时，常借助递归或栈实现"}, {"label": "D", "text": "DFS 只能用于二叉树，不能用于普通树"}]}', '{"correctIndex": 2}', NULL, '["DFS", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C14', 'choice', '{"stem": "小朋友们去邻居拜年，每个家里有不同数量的糖果。规则是不能连续进入两个相邻的房子。目标是拿到最多糖果。补全代码横线。\ndp[0] = nums[0];\ndp[1] = max(nums[0], nums[1]);\nfor (int i = 2; i < size; i++) {\n  dp[i] = ________;\n}", "options": [{"label": "A", "text": "dp[i-1] + nums[i]"}, {"label": "B", "text": "max(dp[i-1], dp[i-2] * nums[i])"}, {"label": "C", "text": "max(dp[i-1], dp[i-2] + nums[i])"}, {"label": "D", "text": "dp[i-2] + nums[i]"}]}', '{"correctIndex": 2}', NULL, '["动态规划", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-C15', 'choice', '{"stem": "元宵节晚上，小朋友沿着一条发光石板路前进，每次可向前走 1 块或 2 块石板。动态规划定义如下：dp[i] = dp[i-1] + dp[i-2]，下面关于 dp[i] 的含义最合适的是（）。", "options": [{"label": "A", "text": "走到第 i 块石板的不同走法数量"}, {"label": "B", "text": "走到第 i 块石板时，已经走过的石板总数"}, {"label": "C", "text": "从第 i 块石板走回起点的最少步数"}, {"label": "D", "text": "从第 i 块石板走回起点的最大步数"}]}', '{"correctIndex": 0}', NULL, '["动态规划", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J01', 'judgment', '{"stem": "下面定义了一个表示二维坐标点的类 Point，并提供了一个带参数的构造函数，但第②行 Point b; 会调用编译器自动生成的默认构造函数，将 b.x 和 b.y 初始化为 0.0，程序可以正常编译运行。"}', '{"correct": false}', NULL, '["C++", "构造函数", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J02', 'judgment', '{"stem": "C++ 中的继承支持单继承和多继承，但子类无法直接访问父类的私有成员。"}', '{"correct": true}', NULL, '["继承", "访问控制", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J03', 'judgment', '{"stem": "对如下结构的树（根1，左2右3，2有左4右5），执行使用栈的DFS遍历函数，输出结果是 1 2 3 4 5。"}', '{"correct": false}', NULL, '["DFS", "树遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J04', 'judgment', '{"stem": "若所有字符出现频率相同，则哈夫曼编码一定会得到完全二叉树。"}', '{"correct": false}', NULL, '["哈夫曼编码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J05', 'judgment', '{"stem": "哈夫曼编码是一种变长的前缀编码，在解码时不需要额外的分隔符就能唯一还原，这是因为在哈夫曼树中，任何一个字符的叶子结点都不会成为另一个字符结点的祖先。"}', '{"correct": true}', NULL, '["哈夫曼编码", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J06', 'judgment', '{"stem": "在 C++ 中使用一维数组 vector<int> tree 存储按层序遍历的完全二叉树时，若根节点存储在 tree[0]，则对于任意非空节点 tree[i]，其右孩子（如果存在）必然位于 tree[2*i+2]。"}', '{"correct": true}', NULL, '["完全二叉树", "数组存储", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J07', 'judgment', '{"stem": "在 C++ 中使用栈来非递归地实现二叉树的前序遍历时，为了保证遍历顺序正确，在处理完当前结点后，应该先将该结点的左孩子压入栈中，然后再将右孩子压入栈中。"}', '{"correct": false}', NULL, '["栈", "前序遍历", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J08', 'judgment', '{"stem": "设二叉树共有 n 个结点，函数 preorderTraversal 的时间复杂度为 O(n)，空间复杂度为 O(h)，其中 h 为树高。"}', '{"correct": true}', NULL, '["时间复杂度", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J09', 'judgment', '{"stem": "下列代码实现了一个 0-1 背包的一维动态规划代码，内层循环是经典的逆序写法。若将内层循环改成正序遍历（即 for (int j = w[i]; j <= W; j++)），仍能得到正确答案。"}', '{"correct": false}', NULL, '["动态规划", "背包问题", "GESP-6"]', 4, 1775530000000);
INSERT OR IGNORE INTO questions (id, type, content, answer, explanation, tags, difficulty, created_at) VALUES ('GESP6-202603-J10', 'judgment', '{"stem": "在动态规划问题中，状态空间相同且没有重复计算的情况下，「状态转移方程 + 递推」与「递归 + 记忆化搜索」的时间复杂度通常相同。"}', '{"correct": true}', NULL, '["动态规划", "GESP-6"]', 4, 1775530000000);